import type { Drill } from "./types";

// Agriculture / early drills, keyed by module slug — 25 per module.
// Farmhand / deckhand / field-and-forestry crew member: shift handoffs, breakdown and
// sick-animal reports, weather and safety flags, radio and text messages to the farm
// manager, skipper, and crew. Merged into course.ts.
export const AGRICULTURE_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-agri-early-01","level":"early","profession":"agriculture","title":"The cow-down radio call","scenario":"You find a cow down in the far paddock during morning rounds. She's breathing but can't stand. You key the radio and your instinct is to start with how your rounds went before getting to her.","task":"Say a 1-2 sentence radio call that leads with what's wrong and where.","tips":["First words: cow down, far paddock.","Location and condition before anything else.","Save how you found her for later."],"focus":["clarity","impact"],"placeholder":"Cow down in the far paddock — breathing but can't stand."},
    {"id":"lead-agri-early-02","level":"early","profession":"agriculture","title":"The baler breaks mid-harvest","scenario":"The baler jams and throws a belt with half the field still down and rain forecast tomorrow. You're texting the farm manager, but your draft starts with what you were doing all morning.","task":"Write a 2-sentence text that leads with the breakdown and what it means for today.","tips":["Sentence one: baler is down, belt gone.","Say what it threatens — the rest of the field before rain.","What happened this morning is background, not the headline."],"focus":["clarity","impact"],"placeholder":"Baler's down — thrown belt, half the field still on the ground."},
    {"id":"lead-agri-early-03","level":"early","profession":"agriculture","title":"The sick-calf handoff","scenario":"You're going off shift. Everything's routine except one calf in pen 3 that wouldn't drink this afternoon and needs watching tonight. Your handoff to the evening crew usually starts with the whole day in order.","task":"Give a handoff where the first sentence is the one thing they must watch.","tips":["Lead with the calf: pen 3, off her feed since 2 pm.","Everything that's fine can come after, briefly.","If they remember one line, make it the calf."],"focus":["structure","clarity"],"placeholder":"Watch the calf in pen 3 — she refused her afternoon feed."},
    {"id":"lead-agri-early-04","level":"early","profession":"agriculture","title":"The snagged net","scenario":"You're hauling gear and the net hangs up hard on something below. The skipper is in the wheelhouse. You need to call it up now, not describe the whole haul so far.","task":"Say a one-sentence call to the skipper that names the problem first.","tips":["Problem first: net's snagged, winch loaded up.","Skip the recap of the haul.","Short enough to shout over the deck noise."],"focus":["concision","impact"],"placeholder":"Net's hung up hard — winch is loading."},
    {"id":"lead-agri-early-05","level":"early","profession":"agriculture","title":"Lightning on the horizon","scenario":"You're on the planting crew and spot lightning maybe ten minutes out, with two other crews spread across the block. You get the foreman on the radio. There's no time for a weather report — just the flag.","task":"Say a 1-2 sentence radio message that leads with the risk and the action.","tips":["Lead with lightning and the time you think you have.","Name the action: crews off the block.","Details about direction can follow if asked."],"focus":["clarity","impact"]},
    {"id":"lead-agri-early-06","level":"early","profession":"agriculture","title":"The buried time-off ask","scenario":"You need next Saturday off for your brother's wedding. Your text to the farm manager starts with three sentences about how you know it's a busy stretch and you hate to ask.","task":"Rewrite the text so the ask and the date come first.","tips":["Sentence one: the day you need and why.","Offer your cover plan right after.","Cut the apologizing warm-up — it buries the ask."],"focus":["clarity","concision"],"placeholder":"Could I have Saturday the 14th off? It's my brother's wedding —"},
    {"id":"lead-agri-early-07","level":"early","profession":"agriculture","title":"Cattle near the road","scenario":"A fence is down on the road side and six head are grazing the ditch, twenty metres from traffic. You call the manager. The fence story can wait — the animals near the road can't.","task":"Say a call that leads with the immediate danger.","tips":["First line: cattle out by the road, how many, where.","The broken fence is the cause — mention it second.","Say what you're doing right now."],"focus":["impact","clarity"],"placeholder":"Six head are out on the road ditch by the north gate —"},
    {"id":"lead-agri-early-08","level":"early","profession":"agriculture","title":"Out of teat dip by Thursday","scenario":"You've noticed the teat dip will run out in about three milkings. The manager does the ordering. Your usual message would wander through the whole supply shelf before naming what's short.","task":"Write a 1-2 sentence text that leads with the item and the deadline.","tips":["Item and when it runs out, in sentence one.","One item, one ask — don't pad it with the whole inventory.","Give the reorder lead time if you know it."],"focus":["precision","concision"],"placeholder":"We're out of teat dip after Thursday morning's milking —"},
    {"id":"lead-agri-early-09","level":"early","profession":"agriculture","title":"The burst irrigation line","scenario":"A main line has split and is pooling water at the top of the vegetable block. You've shut the valve. Your text to the manager starts with how you noticed the pressure was odd during your walk.","task":"Rewrite the text to lead with what happened and what you've done.","tips":["Lead with: line burst, valve is off.","Status now beats the story of discovery.","End with what you need — parts, or someone with pipe fittings."],"focus":["clarity","structure"],"placeholder":"Main line split at the top of the veg block — valve's shut off."},
    {"id":"lead-agri-early-10","level":"early","profession":"agriculture","title":"The tagged-out chainsaw","scenario":"On the forestry crew, your saw's chain brake stopped engaging this morning. You've tagged it out. Your note for the crew board drifts through the morning's cutting before mentioning the saw is unsafe.","task":"Write a 2-sentence board note that leads with the tag-out.","tips":["First line: saw 4 is tagged out, chain brake not engaging.","Say clearly: do not use it.","How you found the fault is second-line detail."],"focus":["clarity","impact"],"placeholder":"Saw 4 is tagged out — chain brake won't engage. Don't run it."},
    {"id":"lead-agri-early-11","level":"early","profession":"agriculture","title":"The picking total, not the tour","scenario":"The orchard manager texts asking how the picking went. You did 42 bins against a 40-bin target, but your reply drafts itself as a tour of every row and ladder move.","task":"Write a reply that leads with the number against the target.","tips":["Headline: 42 bins, target was 40.","One supporting line at most.","She asked for the result, not the route."],"focus":["concision","precision"],"placeholder":"42 bins today — two over target."},
    {"id":"lead-agri-early-12","level":"early","profession":"agriculture","title":"The hold count for the skipper","scenario":"The skipper calls down asking what's in the hold before he talks to the buyer. You know: about 900 kg, mostly good size. You tend to start with how the last two strings fished.","task":"Say a one-sentence answer that gives the number first.","tips":["Number first: roughly 900 kg.","Add the one thing the buyer will ask — size grade.","How the strings fished comes only if he asks."],"focus":["precision","concision"],"placeholder":"About 900 kilos, mostly mediums —"},
    {"id":"lead-agri-early-13","level":"early","profession":"agriculture","title":"Calling the vet after hours","scenario":"A ewe is lambing and stuck — one leg back, and you can't shift it. You've got the vet's after-hours line ringing. She'll decide whether to drive out based on your first sentences.","task":"Say the first two sentences of the call, leading with the emergency.","tips":["Lead with what and how urgent: ewe lambing, leg back, stuck.","Say how long she's been pushing.","Your name and the farm can come right after — not before."],"focus":["clarity","precision"],"placeholder":"I've got a ewe stuck lambing — one leg back, and I can't correct it."},
    {"id":"lead-agri-early-14","level":"early","profession":"agriculture","title":"The gate that must stay shut","scenario":"You're leaving a note for tomorrow's crew. The one thing that matters: the ram is in with the ewes now, so the middle gate stays shut. Your draft opens with a recap of today's jobs.","task":"Write a note where the first line is the instruction that can't be missed.","tips":["First line: keep the middle gate shut — ram's in with the ewes.","Then the routine stuff, short.","Write it so a skim still catches the rule."],"focus":["clarity","impact"],"placeholder":"MIDDLE GATE STAYS SHUT — ram is in with the ewes."},
    {"id":"lead-agri-early-15","level":"early","profession":"agriculture","title":"The parts ask hidden in the story","scenario":"You're messaging the mechanic about the feed mixer. What you actually need is a new drive chain, ideally today. Your draft spends four sentences on the noise it was making before naming the part.","task":"Rewrite so the part and the timing come first, symptoms after.","tips":["Lead with the ask: drive chain for the mixer, today if possible.","Give model and symptoms as support.","The mechanic reads the first line to decide whether to come."],"focus":["clarity","structure"],"placeholder":"Need a drive chain for the feed mixer — today if you can."},
    {"id":"lead-agri-early-16","level":"early","profession":"agriculture","title":"Running late for milking","scenario":"Your truck won't start and you'll be 40 minutes late for the 5 am milking. You're texting the manager at 4:20. Your thumb wants to type the whole truck saga first.","task":"Write a text that leads with the new arrival time.","tips":["First words: I'll be there at 5:40.","One line on why, no more.","Offer what helps: start without me, or call Dee."],"focus":["concision","clarity"],"placeholder":"I'll be in at 5:40 — truck won't start."},
    {"id":"lead-agri-early-17","level":"early","profession":"agriculture","title":"The greenhouse heater failed","scenario":"You open the greenhouse at 6 am and it's 4 degrees inside — the heater cut out overnight. The seedlings look okay so far. Your message to the grower starts with your arrival routine.","task":"Write a 2-3 sentence message that leads with the status.","tips":["Lead with: heater failed overnight, house at 4 degrees, plants look okay so far.","Then what you've done — restarted it, or couldn't.","The reader needs the state of the crop before your morning."],"focus":["clarity","structure"],"placeholder":"Heater cut out overnight — house was at 4°C when I opened up."},
    {"id":"lead-agri-early-18","level":"early","profession":"agriculture","title":"The buried paddock question","scenario":"You need one answer from the manager: move the sheep to the river paddock or the hill paddock today? Your draft message explains the grass situation in both before asking anything.","task":"Rewrite so the question is the first sentence.","tips":["Ask first: river or hill paddock for the sheep today?","Then one line of context each way.","A question up front gets answered from the tractor seat."],"focus":["clarity","concision"],"placeholder":"River or hill paddock for the ewes today?"},
    {"id":"lead-agri-early-19","level":"early","profession":"agriculture","title":"The end-of-day report that wanders","scenario":"You text the manager each evening. Tonight's real news: spraying is finished a day early and the sprayer is washed out. Your draft opens with the weather and works through lunch.","task":"Write a 2-sentence report that leads with the result.","tips":["Headline: spraying done, a day early, kit washed out.","Cut the diary entries.","If nothing needs deciding, say so and stop."],"focus":["concision","structure"],"placeholder":"Spraying's finished — a day early. Sprayer's washed out and shedded."},
    {"id":"lead-agri-early-20","level":"early","profession":"agriculture","title":"Glass in the feed alley","scenario":"You've found broken glass scattered along the feed alley — a smashed jar, probably off a passing load. You've barriered it off. The crew group chat needs to know before anyone feeds out.","task":"Write a group message that leads with the hazard and the rule.","tips":["First line: glass in the feed alley — don't feed out there yet.","Say what you've done and what's next.","Where it came from is a footnote."],"focus":["impact","clarity"],"placeholder":"Broken glass in the feed alley — hold off feeding out there."},
    {"id":"lead-agri-early-21","level":"early","profession":"agriculture","title":"Fix it or swap it","scenario":"The old tractor won't start and you know two ways forward: wait for the mechanic (maybe 2 hours) or hitch the loader tractor and lose it from the yard. You need the manager's call, fast.","task":"Write a message that puts the decision first, then the two options in one line each.","tips":["Lead with: need a call on the tractor — fix or swap.","One line per option with its cost.","Make it answerable with one word."],"focus":["structure","clarity"]},
    {"id":"lead-agri-early-22","level":"early","profession":"agriculture","title":"Which block first","scenario":"Rain's due at 2 pm and you can only get one block picked before it hits — the Galas or the Fujis. The orchard manager is in town. Your call has to surface the choice immediately.","task":"Say a 2-sentence phone message that leads with the decision and deadline.","tips":["Open with: one block before rain at 2 — Galas or Fujis?","Give the single fact that matters for each.","Deadline in the first sentence, always."],"focus":["clarity","impact"],"placeholder":"Rain at 2 — I can only get one block in. Galas or Fujis?"},
    {"id":"lead-agri-early-23","level":"early","profession":"agriculture","title":"The gloves you asked for twice","scenario":"You asked the manager last week for new chemical-handling gloves; yours are cracked. Nothing's arrived. Your follow-up draft opens with 'sorry to bother you again, I know things are hectic.'","task":"Write a follow-up that leads with the ask and why it can't wait.","tips":["Lead with: still need the chem gloves — mine are cracked and I'm spraying Thursday.","A date makes the nudge concrete.","Cut the apology; a safety item isn't a bother."],"focus":["clarity","impact"],"placeholder":"Following up on the chem gloves — mine are cracked and I spray Thursday."},
    {"id":"lead-agri-early-24","level":"early","profession":"agriculture","title":"Owning the open gate","scenario":"You left the yard gate unlatched at lunch and the heifers got into the silage face. They're back in now, no harm visible. You have to tell the manager, and your draft buries the confession under the recovery story.","task":"Write a message that leads with what happened and the current status.","tips":["First line: my mistake — gate was unlatched, heifers got to the silage, all back in now.","Status now, then the fix so it can't repeat.","Owning it plainly reads better than burying it."],"focus":["clarity","impact"],"placeholder":"My fault — I left the yard gate unlatched at lunch."},
    {"id":"lead-agri-early-25","level":"early","profession":"agriculture","title":"The voicemail with the point up front","scenario":"The manager doesn't answer, so you're leaving a voicemail: the stock trough pump in the top field has failed and the tank has maybe a day of water. Voicemails get skimmed — the first five seconds decide if he calls back.","task":"Say a voicemail under 20 seconds that leads with the problem and the ask.","tips":["First five seconds: top-field pump is dead, one day of water left.","Then the ask: call me back before noon.","Name and time at the end, not the start."],"focus":["concision","impact"],"placeholder":"Top-field trough pump's dead — tank has about a day left."}
  ],
  "start-with-the-audience": [
    {"id":"audience-agri-early-01","level":"early","profession":"agriculture","title":"The breakdown, translated","scenario":"The mower's PTO shear bolt has gone twice today. You could tell the farm manager exactly that, but what he actually needs to know is what it does to the mowing schedule and whether he should ring the dealer.","task":"Write a 2-3 sentence text framed around what it means for the schedule, not the mechanics.","tips":["Lead with the effect: mowing stops until we solve this.","Translate 'shear bolt' into 'it keeps stopping and may be a bigger fault'.","End with the decision he can make: dealer, or keep swapping bolts."],"focus":["audience","clarity"],"placeholder":"Mowing's stopped — the mower keeps breaking the same part."},
    {"id":"audience-agri-early-02","level":"early","profession":"agriculture","title":"What the vet needs first","scenario":"You're phoning the vet about a heifer. Your instinct is to tell the story from the start of your shift. The vet triages on a few facts: what animal, what signs, since when, eaten or not, temperature if you have it.","task":"Say a 3-4 sentence phone report giving the vet exactly what she triages on.","tips":["Animal, signs, and duration in the first two sentences.","Skip your shift story — she doesn't need it.","Have the temperature ready; say if you don't."],"focus":["audience","precision"],"placeholder":"Two-year-old heifer, off feed since yesterday evening, temp is 40.1."},
    {"id":"audience-agri-early-03","level":"early","profession":"agriculture","title":"First morning for the new hand","scenario":"A new worker starts today and you're showing him the calf-feeding round. You keep saying things like 'the usual mix' and 'the far shed' — shorthand that means nothing to someone on day one.","task":"Give a 3-4 sentence spoken run-through with zero farm shorthand.","tips":["Name places and amounts he can actually find: 'the grey shed past the silos, 2 litres per calf'.","Assume he knows nothing about this farm — because he doesn't.","One round, in order, no nicknames."],"focus":["audience","clarity"]},
    {"id":"audience-agri-early-04","level":"early","profession":"agriculture","title":"Texting the owner, not the crew","scenario":"The farm owner — who visits monthly and doesn't know the daily detail — texts asking how lambing is going. Your crew-style answer would be percentages, mob numbers, and paddock names she won't recognize.","task":"Write a 2-3 sentence reply pitched at what the owner cares about.","tips":["Big picture first: going well or not, losses low or high.","Skip mob numbers and paddock names — use plain totals.","One concrete detail makes it credible; ten make it unreadable."],"focus":["audience","concision"],"placeholder":"Lambing's going well — about 300 on the ground, losses lower than last year."},
    {"id":"audience-agri-early-05","level":"early","profession":"agriculture","title":"Radio to the other crew","scenario":"You need the planting crew on the next block to leave you the water trailer at the boundary track. They don't know your block's layout or your nicknames for the tracks — 'the muddy corner' means nothing to them.","task":"Say a radio message using only landmarks both crews share.","tips":["Use shared reference points: the boundary gate, the culvert, block numbers.","Say when you need it, in clock time.","Confirm they know the spot: ask them to repeat it back."],"focus":["audience","precision"]},
    {"id":"audience-agri-early-06","level":"early","profession":"agriculture","title":"Note for the relief milker","scenario":"A relief milker covers your weekend shift. She's competent but has never used your parlor. Your notes say things like 'the sticky gate' and 'the usual three slow ones' — clear to you, useless to her.","task":"Rewrite three lines of your note so a stranger to the parlor can act on them.","tips":["Replace nicknames with numbers: cow 214, gate at bail 6.","Say what to do, not just what's quirky.","Read it back as her: could you follow it cold?"],"focus":["audience","clarity"],"placeholder":"Gate at bail 6 sticks — lift it as you swing it."},
    {"id":"audience-agri-early-07","level":"early","profession":"agriculture","title":"Why we bleed the fish now","scenario":"A green deckhand keeps stacking fish unbled when the pace picks up. He's not lazy — nobody's told him why it matters. Price is set on quality, and unbled fish grade down.","task":"Explain in 2-3 spoken sentences why bleeding comes first, in terms he'll care about.","tips":["Tie it to his stake: the crew share is paid on grade.","One plain cause-and-effect: unbled fish grade down, downgrades cost real money.","Skip the lecture — one reason, clearly, beats five."],"focus":["audience","impact"],"placeholder":"Every fish that goes down unbled grades lower — and the share's paid on grade."},
    {"id":"audience-agri-early-08","level":"early","profession":"agriculture","title":"The agronomist vs the manager","scenario":"You spotted yellowing in the young wheat. To the agronomist you'd describe leaf position, pattern, and paddock history. The manager just needs to know something's wrong, where, and that you've called it in.","task":"Write the 2-sentence version for the manager.","tips":["Manager version: what's wrong, where, what you've done about it.","Save the leaf detail for the agronomist.","One audience per message — don't write both at once."],"focus":["audience","concision"],"placeholder":"Patchy yellowing in the young wheat on the flats — I've sent photos to the agronomist."},
    {"id":"audience-agri-early-09","level":"early","profession":"agriculture","title":"The question they can answer in one go","scenario":"You want to ask the senior stockman which drench to use on the weaner lambs. Your draft is just 'which drench for the lambs?' — but he'll need to know which mob, their weight range, and what they had last time.","task":"Rewrite the question so he can answer in a single reply.","tips":["Give what he needs to decide: mob, rough weights, last drench and when.","One question, all its context, one message.","Make his answer a product name, not three follow-up questions."],"focus":["audience","precision"],"placeholder":"Which drench for the weaner mob (about 30 kg, last done with…"},
    {"id":"audience-agri-early-10","level":"early","profession":"agriculture","title":"The safety rule, for a 16-year-old","scenario":"A high-schooler joins the summer crew tomorrow and you're told to brief her on the quad-bike rule: no passengers, helmet always, walking pace in the yard. Recited as policy, it won't stick.","task":"Say the briefing in 3 sentences that a 16-year-old will actually remember.","tips":["Make it concrete: what she does, not what the policy says.","Give the one reason that lands — quads roll, and rolls kill.","Check understanding: ask her to say it back."],"focus":["audience","impact"]},
    {"id":"audience-agri-early-11","level":"early","profession":"agriculture","title":"What the alarm code means for him","scenario":"The milk vat alarm shows code E3 — cooling fault. You text the manager 'vat showing E3.' Unless he has the manual memorized, that tells him nothing about what's at risk or how fast.","task":"Rewrite the text to say what's happening and what's at stake, not the code.","tips":["Translate: vat isn't cooling — this morning's milk is at risk.","Give the time window before it becomes a real loss.","The code goes in brackets at the end, for the technician."],"focus":["audience","impact"],"placeholder":"Vat's not cooling — this morning's milk is at risk if it's not fixed by…"},
    {"id":"audience-agri-early-12","level":"early","profession":"agriculture","title":"The mechanic's version","scenario":"You're leaving a message for the diesel mechanic about the loader. He needs symptoms he can diagnose from: what it does, when it started, hours on the machine, any warning lights. Your draft is mostly how annoying it's been.","task":"Write a 3-sentence message with only what the mechanic can use.","tips":["Machine, model, hours, symptom, when it started.","Describe what it does, not how you feel about it.","Note anything you've already tried, so he doesn't repeat it."],"focus":["audience","precision"],"placeholder":"Loader's losing power uphill under load — started Tuesday, about 6,400 hours."},
    {"id":"audience-agri-early-13","level":"early","profession":"agriculture","title":"Heads-up to the neighbour","scenario":"You're spraying the boundary paddock Thursday morning if the wind stays down. The neighbour keeps bees two fields over. He doesn't need your tank mix — he needs what, when, and what he might do about his hives.","task":"Write a 2-3 sentence courtesy text pitched at the beekeeper's concerns.","tips":["Say when and where, in his terms: the paddock along his east fence.","Name the thing he cares about: bee-safe timing, or not.","Invite the conversation: happy to shift the timing if it helps."],"focus":["audience","clarity"]},
    {"id":"audience-agri-early-14","level":"early","profession":"agriculture","title":"Tide window for the green deckhand","scenario":"The new deckhand asks why you're rushing to get the gear stowed — you leave in 40 minutes or wait six hours. He doesn't know what a tide window is, and 'we'll miss the bar crossing' means nothing to him yet.","task":"Explain the rush in 2 plain sentences a first-tripper understands.","tips":["Plain cause and effect: the water gets too shallow to cross safely after 3 pm.","Then the consequence for him: stow now or sit in the harbour six hours.","Teach the term after the meaning: 'that's the tide window.'"],"focus":["audience","clarity"],"placeholder":"After about 3 the bar gets too shallow to cross safely —"},
    {"id":"audience-agri-early-15","level":"early","profession":"agriculture","title":"The foreman wants totals, not trees","scenario":"The forestry foreman radios asking how your planting line is going. You're tempted to talk about the rocky patch, the box you dropped, the bent spade. He's tracking one thing: stems in the ground versus target.","task":"Give a one-sentence radio answer at the altitude he's working at.","tips":["His altitude is numbers: stems planted, percent of target, finish estimate.","Save the rocky patch unless it changes the estimate.","If it does change the estimate, that IS the headline."],"focus":["audience","precision"],"placeholder":"About 1,100 in, on track to finish the line by 4."},
    {"id":"audience-agri-early-16","level":"early","profession":"agriculture","title":"Withholding milk, explained","scenario":"A newer hand asks why cow 214's milk goes in the dump bucket when she looks fine. The real answer involves antibiotic withdrawal periods and tanker testing — but he needs the working version, not the pharmacology.","task":"Explain in 2-3 sentences why her milk is dumped and what happens if it isn't.","tips":["Plain rule first: she was treated, her milk can't go in the vat until Friday.","Then the stake: one treated cow's milk can fail the whole tanker.","Make the action unmissable: red band means dump bucket."],"focus":["audience","impact"],"placeholder":"She had antibiotics Monday — her milk stays out of the vat until Friday."},
    {"id":"audience-agri-early-17","level":"early","profession":"agriculture","title":"One message, one audience","scenario":"The water trough in the hill paddock is leaking. The manager needs to know for the fix; the crew needs to know to check stock water there daily until it's fixed. You're about to write one message to everybody.","task":"Write the crew version only: 1-2 sentences on what they need to do.","tips":["Crew care about the action: check the hill trough every day until it's fixed.","Leave the repair logistics for the manager message.","Mixed-audience messages get half-read by both."],"focus":["audience","clarity"]},
    {"id":"audience-agri-early-18","level":"early","profession":"agriculture","title":"'The usual gate' means nothing","scenario":"You're texting directions to a contractor delivering fence posts: 'come in the usual gate, past where the old shed was, drop them by the new yards.' He has never been to the farm.","task":"Rewrite the directions for someone seeing the farm for the first time.","tips":["Use what he can see from the road: the green mailbox, the second cattle grid.","Distances and turns, not history — 'where the old shed was' is invisible.","End with where to put them and who to call at the gate."],"focus":["audience","precision"],"placeholder":"Take the gravel drive at the green mailbox on Route 12 —"},
    {"id":"audience-agri-early-19","level":"early","profession":"agriculture","title":"Relaying the vet's instructions","scenario":"The vet gave you dosing instructions for the sick heifer: 20 ml twice daily for three days, food withheld till evening. You're passing it to the night shift. If you relay it loosely, the animal pays.","task":"Write a 2-3 sentence handoff that the night crew can follow without calling anyone.","tips":["Numbers exactly as given: 20 ml, twice a day, three days.","Say where the bottle and the syringe are.","State the check: tick the card on the pen door after each dose."],"focus":["audience","precision"],"placeholder":"Heifer in pen 2: 20 ml of the pen-G, 6 am and 6 pm, three days."},
    {"id":"audience-agri-early-20","level":"early","profession":"agriculture","title":"Feed inventory for the owner","scenario":"The owner asks whether there's enough hay to get through winter. You know it in bales, cuts, and shed positions. She thinks in one question: do we buy more or not, and when do we have to decide?","task":"Write a 2-3 sentence answer in her terms, with your working in one line.","tips":["Answer the real question first: yes we're short, or no we're covered.","Convert bales into time: enough until about mid-August.","Give the decision date: if we're buying, order by July."],"focus":["audience","structure"],"placeholder":"We're about six weeks short if winter runs long —"},
    {"id":"audience-agri-early-21","level":"early","profession":"agriculture","title":"Why the crates get iced","scenario":"The buyer's rep at the dock asks why your boat's fish fetch a better grade than the boat next door. The honest answer is icing discipline. Explain it to a rep who talks price and shelf life, not deck work.","task":"Explain your icing routine in 2-3 sentences framed around what the rep cares about.","tips":["His language is quality and shelf life, not scoops and slush.","Cause to effect: cold fast means firmer fish, longer shelf life, better grade.","One concrete habit as proof: iced within ten minutes of the deck."],"focus":["audience","impact"]},
    {"id":"audience-agri-early-22","level":"early","profession":"agriculture","title":"The message the casuals will read","scenario":"Six casual pickers start Monday. You need to tell them what to bring and when to arrive. Your draft reads like a staff memo — long paragraphs, farm jargon, buried times.","task":"Rewrite it as a short message a first-time picker actually reads and follows.","tips":["Times and address first, list what to bring in a list.","Plain words: 'closed shoes', not 'appropriate PPE footwear'.","Cut everything that isn't needed for day one."],"focus":["audience","concision"],"placeholder":"Start Monday 7 am, 480 Orchard Rd. Bring: hat, water bottle, closed shoes."},
    {"id":"audience-agri-early-23","level":"early","profession":"agriculture","title":"Calling the co-op hotline","scenario":"You're calling the co-op's agronomy line about a spray question. The agent answers dozens of calls a day and can only help if you give: crop, growth stage, product, and what you want to know. Your draft opening is a story about the season.","task":"Say a 2-3 sentence opening that gives the agent exactly what she needs to route your question.","tips":["Crop, stage, product, question — in that order.","She can't see your paddock; give the facts she'd ask for anyway.","One question per call segment; don't stack three."],"focus":["audience","precision"],"placeholder":"Spring barley at three leaves — can I tank-mix…"},
    {"id":"audience-agri-early-24","level":"early","profession":"agriculture","title":"The skipper's version of a gear problem","scenario":"You've noticed the second winch hydraulics running hot and slow by end of day. To another deckhand you'd talk fittings and fluid. The skipper hears it as: can we fish tomorrow, and what does it cost if we don't fix it?","task":"Report it to the skipper in 2 sentences at his altitude.","tips":["Lead with the operational risk: winch may not last the week at this rate.","One line of evidence: running hot and slowing by the last strings.","Offer the decision: look at it tonight, or nurse it and book the yard."],"focus":["audience","impact"],"placeholder":"Second winch is running hot and slowing by the last strings —"},
    {"id":"audience-agri-early-25","level":"early","profession":"agriculture","title":"Same fact, two readers","scenario":"The grain dryer will be down for a day while a part arrives. The manager needs the schedule impact; the harvest crew needs to know what to do with tomorrow's loads. You tend to send the same text to both.","task":"Write both texts — one line each — showing how the same fact changes shape per reader.","tips":["Manager: dryer down Tuesday, part due Wednesday, here's the backlog risk.","Crew: tip tomorrow's loads into the flat store, not the dryer bay.","Notice what each version leaves out — that's the skill."],"focus":["audience","clarity"]}
  ],
  "structure-that-carries": [
    {"id":"structure-agri-early-01","level":"early","profession":"agriculture","title":"The three-bucket handoff","scenario":"Your end-of-shift handoff is a stream of everything you remember, in the order you remember it. The evening crew keeps missing things. The same facts, grouped, would land: animals, machines, jobs left.","task":"Rewrite tonight's handoff under three headings — animals, machines, jobs left — one or two lines each.","tips":["Name the buckets out loud: 'Three things — stock, gear, and what's left.'","Put each fact in exactly one bucket.","Inside each bucket, most urgent first."],"focus":["structure","clarity"],"placeholder":"Stock: all fed, watch the pen-3 calf. Gear: baler belt on order. Left to do:"},
    {"id":"structure-agri-early-02","level":"early","profession":"agriculture","title":"SCQA for the rotation change","scenario":"You think the milking rotation should change — the same two people always get the 4:30 am start and one of them is burning out. You want to raise it with the manager without it sounding like a moan.","task":"Frame the ask in four sentences: situation, complication, question, your suggested answer.","tips":["Situation: how the roster works now, neutrally.","Complication: what it's causing — fatigue, a mistake, a resignation risk.","Question then answer: should we rotate the early start? Here's a fair pattern."],"focus":["structure","impact"]},
    {"id":"structure-agri-early-03","level":"early","profession":"agriculture","title":"PREP: how's the west block?","scenario":"The manager catches you at the fuel shed: 'How's the west block looking?' You know the answer but you tend to think out loud, wandering through details until you land somewhere.","task":"Answer aloud in four beats: point, reason, example, point again.","tips":["Point: it's ready to graze by Thursday.","Reason and one example: growth this week, the measure you took at the gate.","Restate the point in one closing line — then stop."],"focus":["structure","concision"],"placeholder":"West block's ready by Thursday. Growth this week has been…"},
    {"id":"structure-agri-early-04","level":"early","profession":"agriculture","title":"The supply list, grouped","scenario":"Your supply request to the manager is fourteen items in the order you noticed them: twine, ear tags, a rake handle, teat dip, chain oil, gloves… He skims it, orders half, and the urgent things wait.","task":"Regroup the same list into 'need this week' and 'when convenient', urgent first.","tips":["Two groups beat fourteen loose items.","Inside 'this week', add the day each runs out.","Put the group label before the items, not after."],"focus":["structure","precision"],"placeholder":"Need this week: teat dip (out Thu), chain oil (out Fri)…"},
    {"id":"structure-agri-early-05","level":"early","profession":"agriculture","title":"The week-off handoff note","scenario":"You're off for a week and someone else covers your run. Everything lives in your head: feed amounts, the temperamental pump, which ewes are close to lambing, where the spare keys hang. A brain-dump note will fail them.","task":"Outline the note's structure first — 4-5 headings in the order the cover person needs them — then write the first heading's content.","tips":["Order by their day, not your memory: morning round, then afternoon, then 'if something breaks'.","One heading for 'call me if' — keep it short and real.","Structure first, prose second."],"focus":["structure","audience"]},
    {"id":"structure-agri-early-06","level":"early","profession":"agriculture","title":"The incident report skeleton","scenario":"A trailer came unhitched on the lane yesterday — no one hurt, gate post destroyed. The manager needs it written up. Your draft mixes what happened, what you think caused it, and what should change, all interleaved.","task":"Write the report in four labelled parts: what happened, when and where, what was done, what should change.","tips":["Keep 'what happened' to observable facts — no blame, no guesses.","Causes and fixes get their own section, clearly marked as your view.","Times and places exact; the rest brief."],"focus":["structure","precision"],"placeholder":"What happened: the stock trailer came off the ball at the lane bend, about 3:40 pm."},
    {"id":"structure-agri-early-07","level":"early","profession":"agriculture","title":"Morning briefing, in order","scenario":"Two new crew members start today and you're giving the morning briefing. Your usual style is to answer questions as they come up, which means the day's plan arrives in fragments.","task":"Give a spoken briefing in this order: the one goal for today, the three tasks, who does what, then questions.","tips":["Goal first — 'today we get the east field baled before rain.'","Then tasks in the order they'll happen.","Hold questions to the end and say so kindly up front."],"focus":["structure","clarity"]},
    {"id":"structure-agri-early-08","level":"early","profession":"agriculture","title":"Three things on the radio","scenario":"You have three unrelated items for the skipper: the bilge pump cycled twice, you're down to one box of gloves, and the buyer called asking about Friday. Radioed as one run-on, he'll retain the last item only.","task":"Say the radio message with a count up front and each item numbered.","tips":["Open with the count: 'Three things.'","One breath per item, numbered.","Put the item needing action first, not last."],"focus":["structure","concision"],"placeholder":"Three things. One — bilge pump's cycled twice since noon…"},
    {"id":"structure-agri-early-09","level":"early","profession":"agriculture","title":"A logbook entry that carries","scenario":"Your machinery-log entries read like diary lines: 'greased the header, seemed fine, bit noisy later.' Six months on, nobody — including you — can tell what was done, what was observed, and what was left outstanding.","task":"Rewrite one entry with three fixed parts: work done, observations, outstanding.","tips":["Same three parts every entry — the format does the remembering.","Observations are facts with numbers where possible.","'Outstanding' is a promise to the next reader; make it specific."],"focus":["structure","precision"],"placeholder":"Done: greased header bearings. Observed: whine from left side above 1,800 rpm. Outstanding:"},
    {"id":"structure-agri-early-10","level":"early","profession":"agriculture","title":"Group by machine or by urgency?","scenario":"You've got six equipment issues to report: two on the loader, one on the quad, three on the irrigator — but only two of the six actually stop work. You could group by machine or by urgency, and the choice changes what gets fixed first.","task":"Write the report grouped by urgency — 'stops work now' vs 'book it in' — and note the machine on each line.","tips":["Pick the grouping that matches the reader's decision: what to fix first.","Two urgent items get the top and a reason each.","The other four get one line each, no drama."],"focus":["structure","impact"]},
    {"id":"structure-agri-early-11","level":"early","profession":"agriculture","title":"The storm-prep message","scenario":"A big blow is forecast for tonight. Preparation is in your head as a jumble: tie the shed doors, move the heifers off the flood flat, fuel the generator, bring the calf pens inside. The crew chat needs it as a plan, not a jumble.","task":"Write the message as an ordered list — most critical first — with who-does-what if you can name it.","tips":["Order by consequence: flooding stock beats a banging door.","Number the items so people can claim them: 'I've got 2.'","End with the check: reply done as you finish each."],"focus":["structure","impact"],"placeholder":"Storm tonight. In order: 1) Heifers off the flood flat by 5…"},
    {"id":"structure-agri-early-12","level":"early","profession":"agriculture","title":"Setting the nets, step by step","scenario":"You're teaching the new deckhand to set the nets. Your explanation keeps doubling back — 'oh, before that you need to…' — because you're narrating from memory instead of from sequence.","task":"Explain the set in 4-5 numbered steps, in strict order, one sentence each.","tips":["Walk it mentally bow to stern before you speak.","Each step starts with a verb.","Flag the one dangerous moment separately and clearly."],"focus":["structure","clarity"]},
    {"id":"structure-agri-early-13","level":"early","profession":"agriculture","title":"One point, three legs","scenario":"Your weekly report to the manager is a list of twelve things you did. What he'd actually use: one governing headline for the week, held up by no more than three supporting points.","task":"Write the report as one headline sentence plus three supporting bullets.","tips":["Find the sentence the twelve items add up to.","Each bullet supports the headline — if it doesn't, cut or park it.","Three bullets maximum; discipline is the exercise."],"focus":["structure","concision"],"placeholder":"Week's headline: we're ready for silage a week early. 1)…"},
    {"id":"structure-agri-early-14","level":"early","profession":"agriculture","title":"The rambling voicemail, rebuilt","scenario":"A contractor left you a three-minute voicemail about tomorrow's fencing job — materials, timing, a gate access problem, and a question, all tangled. You're forwarding the substance to the manager by text.","task":"Reduce the voicemail to a structured text: what's happening, the one problem, the one question needing an answer.","tips":["Three labelled lines beat three minutes of audio.","Isolate the question — that's what the manager must act on.","Times and quantities survive; the rambling doesn't."],"focus":["structure","concision"],"placeholder":"Fencing starts 8 am tomorrow. Problem: they can't get the truck through the creek gate. Question:"},
    {"id":"structure-agri-early-15","level":"early","profession":"agriculture","title":"Ten observations, three buckets","scenario":"You walked the whole farm this morning and noticed ten things: a leaning post, thistles spreading, a slow trough, a limping ewe, low diesel, and more. Fired off as ten texts, they'd be noise.","task":"Sort your ten observations into three buckets you name yourself, then write the one-line summary of each bucket.","tips":["Good buckets follow action: fix now, watch, plan for.","Name the bucket before listing its contents.","If one item is genuinely urgent, it goes first and alone."],"focus":["structure","clarity"]},
    {"id":"structure-agri-early-16","level":"early","profession":"agriculture","title":"The dock handoff","scenario":"You're coming off the boat and the relief crew takes her out in an hour. Your handoff needs three clean layers: the catch and paperwork, the state of the gear, the state of the boat. Mixed together, something gets missed at sea.","task":"Give the handoff in those three parts, one or two sentences each, spoken.","tips":["Announce the parts first: 'Catch, gear, boat — in that order.'","Boat issues last but loudest — that's what bites them offshore.","End by asking what they want more detail on."],"focus":["structure","clarity"],"placeholder":"Catch, gear, boat. Catch: 900 kilos landed, dockets signed…"},
    {"id":"structure-agri-early-17","level":"early","profession":"agriculture","title":"The fencing pitch, framed","scenario":"You want the manager to replace the rotten fence line on the road boundary rather than keep patching it. Blurted as 'we should really do the road fence,' it goes nowhere. Framed — situation, complication, resolution — it's a case.","task":"Write a 4-5 sentence pitch: what's there now, why patching is failing, what you propose.","tips":["Situation in one line: 400 m of 30-year-old fence, patched six times this season.","Complication is the cost of doing nothing: stock on the road.","Land on a single clear proposal with a rough price."],"focus":["structure","impact"]},
    {"id":"structure-agri-early-18","level":"early","profession":"agriculture","title":"PREP: pick today or wait?","scenario":"The orchard manager asks whether you'd pick the Braeburns today or give them three more days. You have a view. Delivered as a wander through sugar levels and weather maybes, it sounds like no view at all.","task":"Answer aloud in PREP form: your call, the reason, one piece of evidence, your call again.","tips":["Commit in sentence one: wait three days.","One reason, one number — the pressure-test or brix reading you took.","Close by repeating the call so it's unmissable."],"focus":["structure","clarity"],"placeholder":"I'd wait three days. The fruit's still testing firm —"},
    {"id":"structure-agri-early-19","level":"early","profession":"agriculture","title":"The whiteboard, in order of need","scenario":"The crew whiteboard is a graveyard of notes in the order people wrote them. Tomorrow's first job is buried under last week's reminders. You're rewriting it before you leave tonight.","task":"Rewrite the board in three zones: first thing tomorrow, this week, standing notes.","tips":["The top of the board is tomorrow morning — nothing else.","Standing rules live in their own corner, not mixed with jobs.","Erase what's done; a cluttered board hides the one thing that matters."],"focus":["structure","clarity"]},
    {"id":"structure-agri-early-20","level":"early","profession":"agriculture","title":"The calving-watch handoff","scenario":"Three cows are close to calving and the night check passes to a crewmate. He needs a structure he can act on at 2 am: which cows, what signs mean trouble, and exactly who to call when.","task":"Write the handoff in three labelled parts: the cows, the trouble signs, the call tree.","tips":["Identify cows by tag number, not description.","Trouble signs as if-then lines: if pushing over an hour with no feet showing, call.","The call order with actual phone numbers — 2 am is no time to search."],"focus":["structure","precision"],"placeholder":"Cows: 87, 142, 209 in the near paddock. Trouble signs: pushing more than an hour…"},
    {"id":"structure-agri-early-21","level":"early","profession":"agriculture","title":"What I did today, in shape","scenario":"The timesheet has a notes field and yours reads like a run-on sentence: 'moved stock fixed trough helped with drenching moved stock again tidied shed.' Payroll and the manager both read these; shape makes them useful.","task":"Rewrite the day's notes grouped by job with rough hours on each.","tips":["Group repeat work: 'stock moves (x2) — 2 hrs'.","Hours per group, adding to the day.","One outstanding item at the end if something carried over."],"focus":["structure","precision"]},
    {"id":"structure-agri-early-22","level":"early","profession":"agriculture","title":"Three problems, three paragraphs","scenario":"You have three genuinely separate problems for the manager: a sick ewe, a dispute over Saturday's roster, and a broken gate closer. Your draft weaves between them and none lands.","task":"Rewrite as three clearly separated parts, each with its own one-line ask.","tips":["One problem per paragraph, hard separation, labels help.","Each part ends with its own ask — decide, order, or just know.","Order them by urgency, and say that's the order."],"focus":["structure","clarity"],"placeholder":"Three separate things, in order of urgency. 1) The sick ewe:"},
    {"id":"structure-agri-early-23","level":"early","profession":"agriculture","title":"Overview before steps","scenario":"You're teaching a new hand to run the grain auger. You usually dive into step one, and ten minutes later he can operate it but has no idea what it's for or what can go wrong. Big picture first would fix that.","task":"Say a 2-sentence overview — what the machine does and the one danger — before any steps.","tips":["Frame first: this moves grain from the pit to the silo; the danger point is the intake.","One overview, one danger, then steps.","People follow steps better when they know the destination."],"focus":["structure","audience"],"placeholder":"Before I show you the buttons: this auger moves grain from the pit up to the silo, and the one place it can hurt you is…"},
    {"id":"structure-agri-early-24","level":"early","profession":"agriculture","title":"Three breakdowns, one idea","scenario":"The quad has had three flat tyres in a fortnight, all on the same track past the old shed. You could report flat number three — or report the pattern, which is the actual news.","task":"Write a message with the governing idea first, then the three incidents as evidence.","tips":["The idea: something on that track is causing punctures — stop using it until it's swept.","Each incident gets a date and one line.","A pattern with a recommendation beats three separate moans."],"focus":["structure","impact"],"placeholder":"Something on the old-shed track is puncturing tyres — three flats in two weeks, all there."},
    {"id":"structure-agri-early-25","level":"early","profession":"agriculture","title":"Tomorrow, in three parts","scenario":"Rain's due at noon tomorrow, which reshapes the whole day. You're posting the plan tonight: the dry-window jobs, the wet-safe jobs, and the call-off point. Written as a paragraph, half the crew will misread it.","task":"Write tomorrow's plan in three labelled parts with the decision point stated.","tips":["Part 1: before rain — the jobs that must beat noon.","Part 2: after rain — indoor and shed jobs.","State the trigger plainly: if it's raining by 11, we switch."],"focus":["structure","clarity"],"placeholder":"Tomorrow, rain due at noon. Before rain: finish baling the east field…"}
  ],
  "cut-to-the-bone": [
    {"id":"concise-agri-early-01","level":"early","profession":"agriculture","title":"The 60-word radio call","scenario":"Your radio calls run long: 'Yeah hi, it's me, just calling to let you know that I'm up at the top block and I was just thinking that maybe...' The channel is shared and everyone waits while you wind up.","task":"Cut a typical 60-word transmission of yours to under 15 words without losing the message.","tips":["Radio grammar: who, where, what, over.","Delete every wind-up word — 'just', 'yeah', 'I was thinking'.","If it needs discussion, say 'call me' and clear the channel."],"focus":["concision","clarity"],"placeholder":"Top block — sprayer's done, moving to the flats. Over."},
    {"id":"concise-agri-early-02","level":"early","profession":"agriculture","title":"'Just wondering if maybe'","scenario":"Your text to the manager reads: 'Hey, sorry to bother you, just wondering if maybe it would be possible to potentially get the water pump looked at sometime when someone gets a chance?' The pump matters; the hedges bury it.","task":"Rewrite the text with every hedge removed.","tips":["Cut 'just', 'maybe', 'possibly', 'sometime', 'when someone gets a chance'.","Direct isn't rude: 'The water pump needs looking at this week.'","One hedge maximum, and only if you truly are unsure."],"focus":["concision","impact"],"placeholder":"The top-field water pump needs looking at this week —"},
    {"id":"concise-agri-early-03","level":"early","profession":"agriculture","title":"The whiteboard essay","scenario":"Your note on the dairy whiteboard is six lines explaining that the vat wash cycle didn't complete and needs rerunning before the next milking, including how you noticed. It could be one line.","task":"Cut the six lines to one that carries the instruction.","tips":["Boards are for instructions, not stories.","Verb first: 'Rerun the vat wash before pm milking.'","If the why matters, it fits in brackets: '(cycle failed 10 am)'."],"focus":["concision","clarity"],"placeholder":"Rerun vat wash before pm milking (cycle failed 10 am)."},
    {"id":"concise-agri-early-04","level":"early","profession":"agriculture","title":"'I just wanted to let you know'","scenario":"Half your messages open with 'I just wanted to let you know that' or 'Quick heads-up to say that'. The reader pays for those words with attention they'd rather spend on the news.","task":"Take three of your typical openings and cut straight to the content.","tips":["Delete the announcement of the message; send the message.","'I wanted to let you know the calves are moved' → 'Calves are moved.'","Meta-commentary is packing foam — none of it survives the cut."],"focus":["concision"],"placeholder":"Calves are moved to the river paddock."},
    {"id":"concise-agri-early-05","level":"early","profession":"agriculture","title":"Halve the evening text","scenario":"Your end-of-day text to the manager runs ten sentences: the weather, the jobs, a digression about the neighbour's dog, the jobs again. He reads it on his phone at dinner. Halve it and he'll actually read it.","task":"Cut a 10-sentence day report to 5 sentences with nothing important lost.","tips":["One sentence per topic; the second sentence is usually a repeat.","The weather stays only if it changed a decision.","Read the survivors aloud — cut what you'd skip if you were him."],"focus":["concision","structure"]},
    {"id":"concise-agri-early-06","level":"early","profession":"agriculture","title":"The apology-wrapped boots","scenario":"Your work boots have split and site rules say no work without them. Your message stacks three apologies around a simple need: 'Sorry to be a pain… I hate asking… sorry again.' The request is legitimate; the padding isn't.","task":"Rewrite the request in two sentences with zero apologies.","tips":["State the fact and the need: boots have split, I need a replacement pair before Monday.","A legitimate ask needs no sorry.","Politeness is 'thanks', not three apologies."],"focus":["concision","impact"],"placeholder":"My work boots have split. I need a replacement pair before Monday —"},
    {"id":"concise-agri-early-07","level":"early","profession":"agriculture","title":"The padded logbook","scenario":"Your spray-record entry reads: 'Proceeded to undertake the application of herbicide to the area of the front paddock in the morning period.' The legal record needs facts, not costume.","task":"Rewrite the entry in plain words: what, where, when, how much.","tips":["'Proceeded to undertake the application of' is 'sprayed'.","Records want nouns and numbers: product, rate, paddock, time, wind.","Plain is more professional, not less."],"focus":["concision","precision"],"placeholder":"Sprayed front paddock, 8-10 am. Product/rate: …"},
    {"id":"concise-agri-early-08","level":"early","profession":"agriculture","title":"Each and every, first and foremost","scenario":"Your safety-meeting note is stuffed with doubled words: 'each and every gate', 'first and foremost', 'basic and fundamental', 'now and going forward'. Every pair says one thing twice.","task":"Rewrite the note keeping one word from every redundant pair.","tips":["'Each and every' → 'every'. 'First and foremost' → 'first'.","Doubles add weight, not meaning.","If both words truly differ, keep both — that's rare."],"focus":["concision"],"placeholder":"Every gate gets checked before we leave the yard."},
    {"id":"concise-agri-early-09","level":"early","profession":"agriculture","title":"The 20-second voicemail","scenario":"Your voicemails to the feed rep run two minutes and he calls back asking what you needed. The discipline: one breath of content, one ask, done in 20 seconds.","task":"Say a voicemail under 20 seconds ordering next week's calf feed delivery.","tips":["Name, farm, ask, callback number — nothing else.","Write the one sentence before you dial if it helps.","If it can't fit in 20 seconds, it's a call, not a voicemail."],"focus":["concision","clarity"],"placeholder":"It's Sam at Millbrook Farm — we need the usual calf pellets delivered Tuesday."},
    {"id":"concise-agri-early-10","level":"early","profession":"agriculture","title":"The sick-day text","scenario":"You're sick and can't come in. Your draft explains the symptoms, the night you had, and two theories about the cause. The manager needs three facts: you're out, for how long, what's uncovered.","task":"Write a sick-day text in two sentences.","tips":["Out today, back tomorrow if the fever breaks — that's sentence one.","Sentence two: what's uncovered and any critical handoff.","Symptoms are yours to keep."],"focus":["concision","clarity"],"placeholder":"I'm sick and out today — should be back tomorrow. The calves still need their 7 am feed."},
    {"id":"concise-agri-early-11","level":"early","profession":"agriculture","title":"Cut the play-by-play","scenario":"Your breakdown report relives the whole event: 'So I was coming up the lane and I heard a sort of clunk, so I stopped, and then I got out, and then I looked underneath, and then…' The reader needs the finding, not the film.","task":"Cut a play-by-play report to the finding plus one line of relevant history.","tips":["Report the noun, not the journey: 'Front driveshaft guard is hanging loose.'","One line of history only if it aids diagnosis: 'started after the creek crossing.'","'And then' is the tell — every 'and then' is a cut."],"focus":["concision","clarity"],"placeholder":"Front driveshaft guard on the ute is hanging loose — started after the creek crossing."},
    {"id":"concise-agri-early-12","level":"early","profession":"agriculture","title":"The rain plan in one line","scenario":"Rain arrived early and the picking plan just changed. The crew group chat needs the new plan now, while eight people stand under the shed eaves checking phones. Your draft is a paragraph.","task":"Write the new plan as one line everyone understands in five seconds.","tips":["One line: what we're doing now and where.","Names only if tasks differ by person.","Send the one line now; details can follow when it matters."],"focus":["concision","impact"],"placeholder":"Rain's set in — everyone to the packing shed, grading till it clears."},
    {"id":"concise-agri-early-13","level":"early","profession":"agriculture","title":"Excuses off the front","scenario":"Your report on the unfinished fence line opens with three sentences of reasons — the wet ground, the wire delivery, the interruptions — before the fact that it's not done. Reasons stacked in front read as excuses.","task":"Rewrite so the status comes first and one reason follows, then the plan.","tips":["Status first: fence line is 60% done, not finished today.","Pick the ONE reason that actually mattered.","End with the plan: done by Thursday lunch."],"focus":["concision","structure"],"placeholder":"Fence line's 60% done — I lost the afternoon to the wire delivery. Done by Thursday lunch."},
    {"id":"concise-agri-early-14","level":"early","profession":"agriculture","title":"What the night shift doesn't need","scenario":"Your handoff note to the night calving check includes everything from your whole day — most of which they can't act on at midnight. Their shift needs maybe four lines of it.","task":"Cut a full-day note down to only what the night shift can use.","tips":["The filter: can they act on it at 1 am? If not, cut it.","Which cows, what signs, who to call — that's the core.","Your day's achievements go in the day log, not the night note."],"focus":["concision","audience"]},
    {"id":"concise-agri-early-15","level":"early","profession":"agriculture","title":"The check-in, checked","scenario":"Your hourly check-in from the remote block: 'Hi, yeah, it's all going fine up here, no problems really, everything's pretty much on track, all good.' Five phrases, one meaning, and the meaning was one word.","task":"Cut the check-in to its actual content.","tips":["'All good, on schedule' — done.","Repetition doesn't add reassurance; it adds airtime.","Save words for when something's wrong — they'll land harder."],"focus":["concision"],"placeholder":"All good on the top block — on schedule."},
    {"id":"concise-agri-early-16","level":"early","profession":"agriculture","title":"The shift-swap ask","scenario":"You want to swap Saturday for Sunday with a crewmate. Your draft spends four sentences explaining your cousin's visit before the ask arrives. He'll say yes or no on the swap, not on the cousin.","task":"Write the swap request in two sentences: ask first, one line of why.","tips":["The ask up front: swap your Sunday for my Saturday?","One line of reason is polite; four is a story.","Make it easy to answer: yes/no, and offer to square it with the roster."],"focus":["concision","clarity"],"placeholder":"Any chance you'd swap — you take my Saturday, I'll take your Sunday?"},
    {"id":"concise-agri-early-17","level":"early","profession":"agriculture","title":"The hedge on the ladder","scenario":"The orchard ladder has a cracked rung and your report reads: 'It kind of feels like it might be a bit dodgy, possibly worth a look at some point maybe.' A safety flag wrapped in that much cotton wool doesn't register as one.","task":"Rewrite the flag with the hedges stripped and the action stated.","tips":["Safety calls don't hedge: 'Ladder 3 has a cracked rung — I've pulled it from use.'","Say what you did, not what someone might consider possibly doing.","Certainty about the fact, clarity about the action."],"focus":["concision","impact"],"placeholder":"Ladder 3 has a cracked rung — I've pulled it from use."},
    {"id":"concise-agri-early-18","level":"early","profession":"agriculture","title":"The gate sign","scenario":"You're making a sign for the road gate during lambing. Your draft: 'Please be aware that it is very important that this gate remains closed at all times due to livestock in this field.' Nobody reads signs that long from a car window.","task":"Write the sign in the fewest words that still work.","tips":["Signs are read at a glance: 'SHUT THE GATE — LAMBS.'","Every extra word shrinks the letters.","The reason, if kept, is one word."],"focus":["concision","impact"],"placeholder":"SHUT THE GATE — LAMBS"},
    {"id":"concise-agri-early-19","level":"early","profession":"agriculture","title":"The feed-store order","scenario":"Your phone order to the feed store wanders: greetings, the weather, how the calves are doing, then finally amounts. The person on the other end is writing an order slip and waiting for numbers.","task":"Say the order as the slip would read: items, quantities, delivery day.","tips":["Order slips want lines: '10 bags 20% calf pellets. 4 mineral blocks. Deliver Thursday.'","Pleasantries take one word: 'Morning.'","Confirm the total back and hang up."],"focus":["concision","precision"],"placeholder":"Morning — order for Millbrook Farm: 10 bags of the 20% calf pellets…"},
    {"id":"concise-agri-early-20","level":"early","profession":"agriculture","title":"Fuel numbers, not narration","scenario":"The manager asked for the week's diesel usage. Your draft narrates each fill-up with what the machine was doing at the time. He wants three numbers: used, remaining, days till a top-up is needed.","task":"Write the reply as those three numbers with one line of context at most.","tips":["Answer in numbers first; narration only if a number is odd.","'Used 410 L, tank's at 30%, order by Friday.'","If one machine drank double, that's your single line of context."],"focus":["concision","precision"],"placeholder":"Used 410 L this week. Tank's at 30% — worth ordering by Friday."},
    {"id":"concise-agri-early-21","level":"early","profession":"agriculture","title":"Undressing the fancy words","scenario":"Somewhere you picked up dressed-up phrases: 'carried out the completion of the feeding', 'undertook the relocation of the mob', 'performed a check in relation to the troughs'. Underneath: fed, moved, checked.","task":"Rewrite three dressed-up lines from your notes in plain verbs.","tips":["Find the buried verb and promote it: 'completion of feeding' → 'fed'.","'In relation to' is never needed.","Plain verbs read faster and sound more competent, not less."],"focus":["concision","clarity"],"placeholder":"Fed the calves, moved the ewe mob to the flats, checked all troughs."},
    {"id":"concise-agri-early-22","level":"early","profession":"agriculture","title":"The one-word answer, delivered","scenario":"The skipper texts: 'Is the bait order confirmed for Friday?' It is. Your thumb starts composing a paragraph about the call with the supplier, the near-mix-up, the delivery window…","task":"Write the reply this question deserves.","tips":["Yes-or-no questions earn yes-or-no answers: 'Yes — confirmed for Friday 6 am.'","Add detail only if it changes what he does.","The near-mix-up story is for the wheelhouse later, if ever."],"focus":["concision","clarity"],"placeholder":"Yes — confirmed for Friday 6 am."},
    {"id":"concise-agri-early-23","level":"early","profession":"agriculture","title":"The weather flag, trimmed","scenario":"Your frost warning to the group chat runs six sentences with two forecast sources compared. The message that matters: frost likely tonight, cover the seedlings, drain the pump before you leave.","task":"Cut the warning to two sentences: the risk and the actions.","tips":["Risk in plain terms: hard frost likely tonight.","Actions as verbs: cover, drain.","Forecast comparisons are for meteorologists — pick one and act."],"focus":["concision","impact"],"placeholder":"Hard frost likely tonight. Cover the seedling trays and drain the wash-down pump before you go."},
    {"id":"concise-agri-early-24","level":"early","profession":"agriculture","title":"Boat-to-boat, minus the padding","scenario":"You're relaying your position and intentions to a nearby boat working the same ground. Marine radio habit pads everything: 'ah, roger that, yeah, we're just, ah, steaming up to the north end there, over.' Clear water, clear words.","task":"Say the position-and-intentions call in one clean sentence.","tips":["Boat name, position, intention, over.","'Ah' and 'just' don't transmit meaning — drop them.","Short calls keep the channel free; that's courtesy, not brusqueness."],"focus":["concision","clarity"],"placeholder":"Sea Star — we're at the north end of the reef, hauling east along the 40-metre line. Over."},
    {"id":"concise-agri-early-25","level":"early","profession":"agriculture","title":"Six lines to three","scenario":"Your note for tomorrow's crew is six lines. Read it as they will — standing in the shed at 6:30 am, boots half on. Three lines survive that reading; your job is choosing which three.","task":"Cut the note from six lines to three, keeping every needed action.","tips":["Keep actions, cut commentary.","Merge lines that share a subject.","Test: could someone do the morning from the three lines alone?"],"focus":["concision","structure"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-agri-early-01","level":"early","profession":"agriculture","title":"'A lot of fish' isn't a number","scenario":"The skipper asks how the last string fished and you say 'pretty good, a lot of fish.' He's deciding whether to set again on this ground or steam east — 'a lot' can't carry that decision.","task":"Restate the report with numbers he can decide on.","tips":["Count what's countable: boxes, kilos, keepers per pot.","Compare to something: double this morning's string.","If you didn't count, estimate and say it's an estimate."],"focus":["precision","impact"],"placeholder":"Eleven boxes off that string — about double the morning one."},
    {"id":"precision-agri-early-02","level":"early","profession":"agriculture","title":"'Seems off' won't help the vet","scenario":"You tell the manager cow 142 'seems a bit off.' The vet will ask: eating or not, temperature, breathing, standing, since when. 'Off' delays her care by exactly one round of questions.","task":"Rewrite the report as observable signs with times.","tips":["Signs you can see: didn't clear her feed at 7 am, standing apart, ears down.","Take the temperature before you report, not after you're asked.","Times matter: 'since this morning' beats 'lately'."],"focus":["precision","clarity"],"placeholder":"142 left half her feed at 7, standing apart from the mob, temp 39.8."},
    {"id":"precision-agri-early-03","level":"early","profession":"agriculture","title":"'Running low' on feed","scenario":"You tell the manager the calf pellets are 'running low.' He orders on lead times — the supplier takes four days. 'Low' might mean two days or two weeks, and the difference is hungry calves.","task":"Restate the stock level in days and units.","tips":["Count the bags and divide by daily use: 6 bags at 2 a day is 3 days.","Report the deadline that follows: order today for Thursday delivery.","'Low' is a feeling; '3 days' is a fact."],"focus":["precision","impact"],"placeholder":"6 bags of calf pellets left — 3 days at current use. Order today to be safe."},
    {"id":"precision-agri-early-04","level":"early","profession":"agriculture","title":"'Acting up' is not a symptom","scenario":"You report the tractor is 'acting up again.' The mechanic can't triage 'acting up' over the phone, so he has to drive out — or worse, guess. What it does, when, and under what load: that's a report.","task":"Rewrite as symptom, condition, and onset in 2 sentences.","tips":["What it does: cuts out — under load, uphill, after 20 minutes warm.","When it started and what changed around then.","Machine hours if you have them; the mechanic thinks in hours."],"focus":["precision","clarity"],"placeholder":"Tractor cuts out under load once it's warm — started Monday, about 20 minutes into work."},
    {"id":"precision-agri-early-05","level":"early","profession":"agriculture","title":"What, so what, now what","scenario":"The trough sensor in the hill paddock reads 15 cm — you know that's a day of water for that mob in this heat. Reporting the raw reading alone makes the manager do the maths you've already done.","task":"Report it in three beats: the reading, what it means, what you propose.","tips":["What: hill trough at 15 cm, dropping since yesterday.","So what: about a day of water for 80 ewes in this heat.","Now what: I'll run the water cart up unless you'd rather fix the pump first."],"focus":["precision","structure"],"placeholder":"Hill trough's at 15 cm — about a day of water for that mob in this heat. I'll run the cart up unless…"},
    {"id":"precision-agri-early-06","level":"early","profession":"agriculture","title":"The rain gauge, read for meaning","scenario":"The gauge shows 42 mm since Friday across three fronts. You could text '42 mm since Friday' — true, but not yet useful. The insight is what it means for the week: ground too wet to drill until Thursday at least.","task":"Turn the readings into one insight sentence, data attached.","tips":["Lead with the meaning: no drilling before Thursday.","The number is your evidence, not your headline.","One insight per message — don't make the reader mine the data."],"focus":["precision","clarity"],"placeholder":"Too wet to drill before Thursday — 42 mm since Friday and the flats are holding water."},
    {"id":"precision-agri-early-07","level":"early","profession":"agriculture","title":"'Soon' is not a time","scenario":"You told the manager you'd have the broken fence stapled up 'soon' and the sheep moved 'later on.' He's coordinating a shearer's visit around your 'soon.' Vague times force everyone else to guess.","task":"Restate both commitments with clock times.","tips":["Pick a time you can hit: fence by 11, sheep moved by 1.","If you're unsure, give the later honest time, not the hopeful one.","A time you keep builds more trust than an early guess you miss."],"focus":["precision","impact"],"placeholder":"Fence will be stapled by 11, and I'll have the ewes moved by 1."},
    {"id":"precision-agri-early-08","level":"early","profession":"agriculture","title":"The skeptic and the new feed","scenario":"You want to tell the manager the new calf feed 'works way better.' He's paying 15% more for it, and a fair question is coming: better how, by how much, compared to what?","task":"Make the claim survive the skeptic: state it with the comparison and numbers you have.","tips":["Name the measure: weight gain, scour cases, feed refusals.","Compare like with like: same age calves, same weeks.","If your evidence is thin, size the claim to fit it: 'early signs, worth a proper trial.'"],"focus":["precision","impact"],"placeholder":"Scour cases are down — one this month against five last month on the old feed, same-age calves."},
    {"id":"precision-agri-early-09","level":"early","profession":"agriculture","title":"The egg count is telling you something","scenario":"You collect the layer-house eggs daily: 310, 305, 298, 291, 284 over five days. Reported as today's number, it's fine. Read as a line, it's a steady fall that wants a cause — feed, light hours, or something in the shed.","task":"Report the trend, not the day, and say what you'd check first.","tips":["The news is the direction: down 26 in five days, steady fall.","Rule-outs show thinking: feed unchanged, no new noise you know of.","Propose the first check — light timer — so the report lands with a next step."],"focus":["precision","structure"],"placeholder":"Egg count's fallen five days straight — 310 down to 284. Feed's unchanged; I'd check the light timer first."},
    {"id":"precision-agri-early-10","level":"early","profession":"agriculture","title":"'Really hot' in the greenhouse","scenario":"You text the grower that the greenhouse got 'really hot' this afternoon. The tomatoes have a threshold — above 35°C the fruit set suffers. 'Really hot' doesn't say whether that line was crossed or for how long.","task":"Rewrite with the peak reading, the threshold, and the duration.","tips":["Number against threshold: peaked at 38 against a 35 limit.","Duration is the damage variable: about 90 minutes over.","End with the control action: vents open now, back to 31."],"focus":["precision","impact"],"placeholder":"House 2 peaked at 38°C — about 90 minutes over the 35 limit. Vents are open, it's back to 31."},
    {"id":"precision-agri-early-11","level":"early","profession":"agriculture","title":"The fuel that doesn't add up","scenario":"The diesel tank gauge says 400 litres but your log of fills says it should hold about 550. That gap is a leak, a metering fault, or fuel walking away — three very different problems. Vague suspicion helps nobody; the numbers might.","task":"Write a report that states the discrepancy precisely without accusing anyone.","tips":["Numbers first: log says 550, gauge says 400, gap of about 150 over two weeks.","Name the innocent explanations alongside the bad one.","Propose the check: dip the tank, log every fill for a week."],"focus":["precision","clarity"],"placeholder":"Fuel log and gauge disagree by about 150 L over two weeks — could be the gauge, a leak, or something else. Worth dipping the tank."},
    {"id":"precision-agri-early-12","level":"early","profession":"agriculture","title":"This trip against last trip","scenario":"Back at the dock, the skipper's brother asks how the trip went. 'Not bad' is your reflex. You actually know: 3,400 kg over four days against 2,900 last trip, but with an extra day at sea.","task":"Give the comparison honestly — both numbers and the catch in them.","tips":["Raw totals mislead: per-day is the honest compare.","3,400 over four days is 850 a day; 2,900 over three is nearly the same.","Precision protects you from sounding better or worse than you are."],"focus":["precision","clarity"],"placeholder":"3,400 kilos in four days — about the same daily rate as last trip, just a longer trip."},
    {"id":"precision-agri-early-13","level":"early","profession":"agriculture","title":"'Lots of weeds' won't book a sprayer","scenario":"You report 'lots of weeds coming through in the barley.' The manager books contractors on area and severity. Which paddock, what weed if you know it, how much of the field, how advanced — that's what turns into action.","task":"Rewrite the report with location, coverage, and stage.","tips":["Coverage as a fraction: patches over maybe a third of the north half.","Name the weed if you can; photo if you can't.","Stage sets urgency: seedling weeds wait a week, flowering ones don't."],"focus":["precision","impact"],"placeholder":"Wild oats through about a third of the north half of the barley — past seedling stage."},
    {"id":"precision-agri-early-14","level":"early","profession":"agriculture","title":"An estimate with legs","scenario":"The foreman asks how long to finish planting the block. 'A couple of days, probably' is your reflex. You have real inputs: 4,200 stems left, your crew plants about 1,500 a day, and Thursday is forecast wet.","task":"Give an estimate built from the numbers, stated with its one condition.","tips":["Show the maths in one phrase: 4,200 left at 1,500 a day.","Name the condition: three days if Thursday stays dry.","An estimate with reasoning can be checked; 'probably' can't."],"focus":["precision","structure"],"placeholder":"Three days — 4,200 stems left at about 1,500 a day — if Thursday stays workable."},
    {"id":"precision-agri-early-15","level":"early","profession":"agriculture","title":"The vat temperature, with meaning","scenario":"The milk vat reads 7°C two hours after milking — it should be at 4 by now. You know the tanker comes at 6 am and milk over temp too long gets rejected. The report needs the reading, the standard, and the clock.","task":"Report it in 2 sentences: reading vs standard, and the deadline it creates.","tips":["Reading against standard: 7 now, should be 4 by this point.","The deadline does the persuading: tanker's at 6 am.","Say what you've checked already — compressor running, doors shut."],"focus":["precision","impact"],"placeholder":"Vat's at 7°C two hours post-milking — should be 4. Tanker's at 6 am, so we've got tonight to sort it."},
    {"id":"precision-agri-early-16","level":"early","profession":"agriculture","title":"'Seems high' needs a denominator","scenario":"You feel like more chicks are dying this batch. Feelings don't fix sheds — rates do. You count: 18 losses from 500 chicks by day 10; the last batch lost 9 of 500 by the same day.","task":"Report the mortality as rates compared, then flag it as worth investigating.","tips":["Same-day comparison: 3.6% by day 10 versus 1.8% last batch.","Double the rate is the headline — say it plainly.","Attach the obvious variables: same feed, colder week, new heater settings."],"focus":["precision","clarity"],"placeholder":"Chick losses are running double last batch — 18 of 500 by day 10, against 9 last time."},
    {"id":"precision-agri-early-17","level":"early","profession":"agriculture","title":"Count the posts before you text","scenario":"You're reporting storm damage to the boundary fence. 'A fair bit of fence down' will get you asked to go count it anyway. You walked it: 14 posts snapped, about 120 metres of wire on the ground, two strainers gone.","task":"Write the damage report with the counts, and what they mean for materials.","tips":["Counts convert straight to a materials order — that's their value.","Walk it before you write it.","Add the one judgment that matters: stock-proof or not tonight."],"focus":["precision","impact"],"placeholder":"Boundary fence: 14 posts snapped, ~120 m of wire down, 2 strainers gone. Not stock-proof — I've moved the mob."},
    {"id":"precision-agri-early-18","level":"early","profession":"agriculture","title":"The cell count is drifting","scenario":"The dairy company's report shows the somatic cell count rising three pickups in a row: 180, 210, 240. Over 400 costs the farm its quality premium. Passing the numbers along raw wastes what you've noticed.","task":"Report it as what-so what-now what for the manager.","tips":["What: SCC up three pickups running, 180 to 240.","So what: the premium's at risk if the trend holds.","Now what: strip and check the usual suspects at tonight's milking."],"focus":["precision","structure"],"placeholder":"Cell count's climbed three pickups straight — 180 to 240. Premium's at risk if it keeps going; I'll strip-check the herd tonight."},
    {"id":"precision-agri-early-19","level":"early","profession":"agriculture","title":"'The brakes feel weird'","scenario":"You tell the manager the quad's brakes 'feel weird.' Someone else rides it tomorrow on the hill tracks. 'Weird' needs to become something a mechanic can find and a rider can respect.","task":"Rewrite as a specific fault description plus the interim action.","tips":["Describe behaviour: lever pulls halfway to the bar before biting, worse when hot.","Say the action you took: parked it, keys in the office.","A vague fault report leaves the danger on the track."],"focus":["precision","impact"],"placeholder":"Quad's front brake pulls halfway to the bar before it bites — I've parked it till it's looked at."},
    {"id":"precision-agri-early-20","level":"early","profession":"agriculture","title":"Measure the stack, don't eyeball it","scenario":"Asked how much hay is left, you nearly say 'plenty, we're fine.' You go count instead: 240 bales, feeding 6 a day, so 40 days — and winter has about 60 to run. 'Plenty' was wrong.","task":"Write the report the count produces, including the shortfall.","tips":["Count, rate, days: 240 bales, 6 a day, 40 days.","Compare to need: 60 days of winter left means 120 bales short.","This is why you measure before reporting — instinct said fine."],"focus":["precision","impact"],"placeholder":"240 bales left at 6 a day — 40 days of feed against about 60 days of winter. We're ~120 bales short."},
    {"id":"precision-agri-early-21","level":"early","profession":"agriculture","title":"Pin down 'later today'","scenario":"The shearing contractor asks when the ewes will be in the yards. 'Later today, sometime after lunch' costs him — his crew of four bills by the hour standing around. He needs a time, or an honest range with a check-in.","task":"Give the commitment as a time or a tight range with a confirmation point.","tips":["A range with an update beats a vague promise: between 1 and 2, I'll text at 12:30.","Count backward from the yards: mustering that mob takes 90 minutes.","His crew's waiting time is the cost of your 'sometime'."],"focus":["precision","audience"],"placeholder":"They'll be in the yards between 1 and 2 — I'll text you at 12:30 when I'm sure."},
    {"id":"precision-agri-early-22","level":"early","profession":"agriculture","title":"The predator report","scenario":"Something got into the lambs overnight. 'We lost some lambs to something' starts a panic without aiming it. You have the facts: three dead, two missing, all from the creek paddock, drag marks toward the tree line, likely last night after 10.","task":"Write the report with counts, location, time window, and evidence — no speculation beyond it.","tips":["Counts and places first: three dead, two missing, creek paddock.","Evidence, labelled as such: drag marks toward the trees.","Say what you'd do tonight: move the mob in, set the camera."],"focus":["precision","structure"],"placeholder":"Three lambs dead, two missing from the creek paddock overnight — drag marks toward the tree line."},
    {"id":"precision-agri-early-23","level":"early","profession":"agriculture","title":"Soil moisture into a decision","scenario":"You probed the potato block at six spots: bone dry in the top 10 cm on the sandy end, decent moisture at depth on the heavy end. The irrigation decision — water now or wait — should fall out of your report, not precede it.","task":"Report the readings and the recommendation they support, in 2-3 sentences.","tips":["Group the readings: sandy end dry to 10 cm, heavy end holding.","Recommendation follows evidence: water the sandy end tonight, heavy end holds till Friday.","Split decisions are fine when the ground splits."],"focus":["precision","clarity"],"placeholder":"Sandy end's dry to 10 cm, heavy end still holding at depth — I'd water the sandy half tonight and leave the rest till Friday."},
    {"id":"precision-agri-early-24","level":"early","profession":"agriculture","title":"The forecast into a plan","scenario":"The forecast says 70% chance of 15-25 mm from 2 pm tomorrow. The crew asks what that means for the harvest plan. Repeating the forecast isn't a plan — converting it into cut-off times and job order is.","task":"Turn the forecast into concrete plan numbers: start time, cut-off, what moves indoors.","tips":["Work back from 2 pm: last load into the shed by 1:30.","Start earlier — say so: on the headers by 6.","State the fallback: if it holds off, we reassess at 1."],"focus":["precision","structure"],"placeholder":"Rain's likely from 2 tomorrow, so we start at 6 and last load's in the shed by 1:30."},
    {"id":"precision-agri-early-25","level":"early","profession":"agriculture","title":"'Almost done' — measured","scenario":"The manager texts asking if the pruning is almost done. 'Almost' has burned you before. You count: 14 rows finished of 20, and the last six are the old gnarly trees that go slower.","task":"Reply with the fraction, the honest pace, and a finish time.","tips":["Fraction first: 14 of 20 rows.","Adjust for reality: the last six rows run slower — say so and why.","Land on a time: done by Thursday midday, not 'nearly there'."],"focus":["precision","clarity"],"placeholder":"14 of 20 rows done. The last six are the old trees, so slower — finished by Thursday midday."}
  ],
  "executive-presence": [
    {"id":"presence-agri-early-01","level":"early","profession":"agriculture","title":"The paddock menu instead of a pick","scenario":"The manager asks which paddock the ewes should go to next. You walked both this morning — the river paddock has better feed and drier ground. But your reply drafts itself as 'either would work, whichever you prefer.' You did the looking; make the call.","task":"Rewrite to recommend one paddock, with the other as the alternative you rejected.","tips":["Your pick and the reason in the first line.","Mention the other paddock and why it lost.","A recommendation shows you walked the ground; a menu hides it."],"focus":["impact","structure"],"placeholder":"I'd put them in the river paddock — better feed and it's drier underfoot. The hill paddock's"},
    {"id":"presence-agri-early-02","level":"early","profession":"agriculture","title":"Fact versus your read on the lame cows","scenario":"Three cows came in lame this week and your message to the manager tangles what you saw with what you think: 'the new track is wrecking their feet, it's obviously the stones.' He needs the facts separated from your theory so he can judge both.","task":"Rewrite separating what you observed from what you think it means, each labeled.","tips":["Facts first: three lame this week, all after using the new track.","Then your read, marked as your read.","Blending them makes the facts look like opinion too."],"focus":["precision","impact"],"placeholder":"Facts: three cows lame this week, all three came in off the new track. My read: the fresh stone is"},
    {"id":"presence-agri-early-03","level":"early","profession":"agriculture","title":"Signposting your first toolbox talk","scenario":"The foreman's away and you're running the morning toolbox talk. You've got three things: the forecast, today's job order, and a hazard on the laneway. Your instinct is to launch straight in and hope it hangs together.","task":"Say the opening that signposts all three points before you start on any of them.","tips":["Open with the map: three things this morning.","Name them in one breath, then take them in order.","A signpost tells the crew you've got hold of the morning."],"focus":["structure","clarity"],"placeholder":"Three things this morning: the weather, the job order, and a hazard on the laneway. First —"},
    {"id":"presence-agri-early-04","level":"early","profession":"agriculture","title":"Cutting the 'probably a dumb idea'","scenario":"You've worked out a better way to run the calf pens that would save half an hour a day. At the crew meeting you start with 'this is probably stupid, but...' and you can see the older hands switch off before you've said the idea.","task":"Say the opening again with the self-undercutting cut out.","tips":["Delete the pre-apology entirely.","State the idea as worth two minutes of their time.","If you don't back it, nobody else will."],"focus":["impact","clarity"],"placeholder":"I've found a way to save us half an hour a day on the calf pens. Here it is:"},
    {"id":"presence-agri-early-05","level":"early","profession":"agriculture","title":"Steady answer on the owner's walkthrough","scenario":"The owner visits monthly and today she stops by the yards and asks how the new heifers are settling in. You know the answer well, but around the owner you tend to mumble, trail off, and end every sentence like a question.","task":"Say a 2-3 sentence answer in flat, steady statements — verdict first.","tips":["Verdict up front: they've settled well, or they haven't.","Statements, not questions — keep your voice level at the end of each line.","One concrete detail makes it credible."],"focus":["clarity","impact"]},
    {"id":"presence-agri-early-06","level":"early","profession":"agriculture","title":"The inspector's question you half-know","scenario":"The dairy inspector asks how often the plate cooler is checked. You know it's on the weekly wash routine but you're not certain it's written down. The temptation is to guess confidently or dissolve into 'um, I think, maybe'.","task":"Say an answer that states what you know plainly and names what you'd confirm.","tips":["Give the part you're sure of as fact: it's checked on the weekly wash.","Name the part you'd verify: whether it's logged, and who signs it.","Calm precision beats confident guessing with an inspector."],"focus":["precision","clarity"],"placeholder":"It's checked every week as part of the wash routine. Whether that's logged, I'd want to confirm with"},
    {"id":"presence-agri-early-07","level":"early","profession":"agriculture","title":"A deckhand's view on the next string","scenario":"The skipper's weighing whether to shoot the gear again on this ground or steam east. You've been watching the last three hauls fall away and you have a view. Deckhands usually keep quiet — but he's asked what you think.","task":"Say your recommendation in 2 sentences: your pick, then the evidence.","tips":["Take a position: I'd steam east.","Back it with what you've seen: each haul lighter than the last.","He can overrule you — but give him a real answer to overrule."],"focus":["impact","concision"],"placeholder":"I'd steam east. The last three hauls have dropped off every time —"},
    {"id":"presence-agri-early-08","level":"early","profession":"agriculture","title":"When the vet asks what you think","scenario":"The vet is looking at a cow that's been off her feed and asks, 'You see her every day — what do you reckon?' You've got a theory: she went downhill after the mob switched to the new silage pit. Don't shrink from it, and don't dress it up as certainty.","task":"Give your read in 2-3 sentences, clearly labeled as your read, with the observation behind it.","tips":["Own it: 'my guess is', then say it plainly.","Anchor it to what you saw and when.","You're the daily eyes — your read is evidence, offered as a read."],"focus":["precision","audience"],"placeholder":"My guess is the new silage pit — she went off her feed two days after we switched, and she's"},
    {"id":"presence-agri-early-09","level":"early","profession":"agriculture","title":"The count with a confidence band","scenario":"The manager asks how many lambs are on the ground in the front mob. You counted 84 this morning but they were moving. Your usual answer — 'I dunno, maybe eightyish? Could be more?' — sounds like you didn't count at all.","task":"Say the number the way someone who counted says it.","tips":["Lead with the number: 84 this morning.","Give the honest band: give or take two or three, they were moving.","Hedging every word erases the counting you actually did."],"focus":["precision","impact"],"placeholder":"84 this morning, give or take a couple — they were on the move while I counted."},
    {"id":"presence-agri-early-10","level":"early","profession":"agriculture","title":"Two quotes, one recommendation","scenario":"You got two quotes for fencing wire like the manager asked. Your text lays them out side by side and ends with 'let me know which you want.' You compared them properly — one is cheaper per roll and the store can deliver Friday.","task":"Rewrite the text so it recommends one supplier and gives the deciding reason.","tips":["Recommendation first, both quotes as support.","Name the decisive factor: price plus Friday delivery.","Don't hide the thinking you already did behind neutrality."],"focus":["impact","structure"],"placeholder":"I'd go with Rural Direct — $4 less a roll and they deliver Friday. The co-op quote"},
    {"id":"presence-agri-early-11","level":"early","profession":"agriculture","title":"Holding your line when the old hand scoffs","scenario":"At smoko you suggest moving the troughs before the mob rotates, and the oldest hand on the crew snorts: 'We've never bothered.' You're right — the far trough is dry and the pump's slow. The test is restating your point without heat and without folding.","task":"Say your reply: hold the position calmly, with the fact that carries it.","tips":["Repeat the point once, level tone, no apology.","Attach the fact: the far trough is dry and the pump takes an hour.","You don't have to win the exchange — just keep the point standing."],"focus":["impact","clarity"],"placeholder":"Maybe not, but the far trough's dry right now and the pump takes an hour to fill it —"},
    {"id":"presence-agri-early-12","level":"early","profession":"agriculture","title":"The update that ends like a question","scenario":"You're giving the orchard manager a verbal update on thinning and every sentence curls up at the end — 'so we're through row twelve? and the fruit set looks heavy?' It makes solid work sound like you're asking permission for it.","task":"Say the same 3-sentence update with every line landing as a statement.","tips":["Drop your pitch at the end of each sentence.","Say the numbers like facts, because they are.","Uptalk makes listeners doubt things they'd otherwise accept."],"focus":["clarity","impact"]},
    {"id":"presence-agri-early-13","level":"early","profession":"agriculture","title":"Pitching the gateway fix at the crew meeting","scenario":"The gateway to the milking platform turns to soup every wet week and everyone gripes about it. You've priced a load of rock and a culvert pipe at about $400. Crew meeting is your moment — one clear proposal, owned.","task":"Say a 3-sentence pitch: the fix, the cost, and what it ends.","tips":["Open with the proposal, not the griping history.","One number: $400, rock and pipe.","Close with the payoff: no more bogged cows and lost time every rain."],"focus":["structure","impact"],"placeholder":"I want to fix the platform gateway properly: a load of rock and a culvert pipe, about $400 all up."},
    {"id":"presence-agri-early-14","level":"early","profession":"agriculture","title":"Verdict first on the new irrigation","scenario":"The owner asks how the new irrigation setup is working out. You've got three weeks of watching it. Your habit is to start with the story of installation week and let her dig for the verdict.","task":"Say a 2-3 sentence answer that opens with the verdict and backs it with one number.","tips":["First sentence is the judgment: it's working, with one catch.","One supporting number: coverage, hours saved, or the dry corner.","She asked for an assessment — give one, not a diary."],"focus":["clarity","concision"],"placeholder":"It's working well — watering time's down from six hours to four. The one catch is the"},
    {"id":"presence-agri-early-15","level":"early","profession":"agriculture","title":"The board note that sounds decided","scenario":"You're leaving a note about the new rule: no quad bikes past the creek crossing until the track's repaired. Your draft reads like a suggestion — 'probably best if we maybe avoid the creek track for now?' Nobody follows a maybe.","task":"Rewrite the note so it reads as a decision, not a mood.","tips":["Plain imperative: no quads past the creek crossing until the track's fixed.","One line of reason is plenty.","Sign it and date it — owned rules get followed."],"focus":["clarity","impact"],"placeholder":"No quads past the creek crossing until the track's repaired — the bank is undercut."},
    {"id":"presence-agri-early-16","level":"early","profession":"agriculture","title":"The radio call that trails off","scenario":"Your radio calls to the foreman tend to die out — 'so yeah, the sprayer's ready whenever, I guess, over.' The message is fine; the ending gives it away. A call should land on the ask, not evaporate.","task":"Say the call again so it ends on a clear question or handoff.","tips":["Finish on the ask: 'do you want me to start on the east block?'","Then stop talking.","A firm ending is half of sounding sure."],"focus":["clarity","concision"],"placeholder":"Sprayer's calibrated and loaded. Do you want me to start on the east block? Over."},
    {"id":"presence-agri-early-17","level":"early","profession":"agriculture","title":"Own the pruning order","scenario":"The orchard manager asks whether the crew should prune the young block or the old block first this week. You know the young block's buds are moving and won't wait. Your draft reply: 'either works!' It doesn't — and you know it.","task":"Write a 2-sentence reply that makes the call and gives the reason.","tips":["Pick: young block first.","Reason in one line: buds are moving, the old block will hold.","Saying 'either works' when it doesn't passes your knowledge back unused."],"focus":["impact","precision"],"placeholder":"Young block first — the buds are already moving and it won't wait. The old block will hold till"},
    {"id":"presence-agri-early-18","level":"early","profession":"agriculture","title":"Fact and judgment on the worn hauler rope","scenario":"You've noticed the hauler rope on the boat is furring badly near the splice. Telling the skipper 'that rope's going to kill someone' mixes alarm with observation. Give him both — separately — so he can weigh it.","task":"Say a 2-sentence report: the observed wear, then your assessment of it.","tips":["Fact: furring and broken strands a metre from the splice.","Assessment, labeled: I don't trust it under full load.","Separating the two makes the alarm more credible, not less."],"focus":["precision","impact"],"placeholder":"The hauler rope's furred with broken strands about a metre off the splice. My read: I wouldn't trust it"},
    {"id":"presence-agri-early-19","level":"early","profession":"agriculture","title":"One point, landed, in the planning meeting","scenario":"Harvest planning meeting, whole crew in the shed. You've got one thing to add: the header can't turn at the top of block 9 with the new fence in, and the plan assumes it can. You tend to wrap your one point in ten sentences of throat-clearing.","task":"Say your point in 2 sentences maximum, then stop.","tips":["Point first: the plan won't work at the top of block 9.","Reason second: the header can't turn inside the new fence.","Stopping on time is what makes the point land."],"focus":["concision","impact"],"placeholder":"One thing on block 9 — the header can't turn at the top since the new fence went in."},
    {"id":"presence-agri-early-20","level":"early","profession":"agriculture","title":"Which face to cut, and why","scenario":"On the forestry block, the crew boss asks whether to start on the north or south face given the wind forecast. You've cut both faces before and the north face leans wrong for a southerly. Give him a real answer.","task":"Say your recommendation with the safety logic in one breath.","tips":["Pick a face and say it first.","The logic in one line: the north face lean fights a southerly.","On safety calls, a clear owned view is worth more than politeness."],"focus":["clarity","impact"],"placeholder":"South face today. The north face lean fights a southerly and that forecast is"},
    {"id":"presence-agri-early-21","level":"early","profession":"agriculture","title":"Disagreeing with the foreman, cleanly","scenario":"The foreman wants to drench the whole mob today; you noticed this morning that thirty of them were drenched by the weekend crew Saturday. Contradicting him in front of the crew feels risky — but double-drenching is worse.","task":"Say a respectful 2-sentence pushback: the fact, then the suggestion.","tips":["Lead with the fact, not 'I disagree': thirty were done Saturday.","Offer the path: run them through and draft off the marked ones.","Facts delivered flat don't read as a challenge."],"focus":["clarity","audience"],"placeholder":"One thing before we start — the weekend crew drenched about thirty of these on Saturday."},
    {"id":"presence-agri-early-22","level":"early","profession":"agriculture","title":"The training ask without the grovel","scenario":"You want the farm to put you through a chainsaw certification course. Your draft message spends three sentences apologizing for the cost and the time off before it even names the course. Ask like it's a fair trade — because it is.","task":"Rewrite the ask: the course, the cost, and what the farm gets back.","tips":["Name the ask in sentence one: the two-day chainsaw cert, $450.","Trade, not favour: certified means I can clear windfall without waiting on contractors.","Cut every 'sorry' — a training request isn't a confession."],"focus":["impact","structure"],"placeholder":"I'd like to do the two-day chainsaw certification next month — $450. It means I can legally"},
    {"id":"presence-agri-early-23","level":"early","profession":"agriculture","title":"The near-miss, told straight","scenario":"A round bale rolled off the loader forks and missed you by a metre. Telling the safety rep, you could shrug it off ('all good, no drama') or blow it up. What serves the farm is the plain version: what happened, why, what would stop a repeat.","task":"Report the near-miss in 3 sentences: event, cause, prevention.","tips":["Say what happened without minimizing: the bale came off, it missed me by a metre.","Name the cause you saw: forks not tilted back on the slope.","Finish with the fix — that's what turns a fright into a rule."],"focus":["structure","precision"],"placeholder":"A bale came off the loader forks this morning and missed me by about a metre. The forks weren't tilted"},
    {"id":"presence-agri-early-24","level":"early","profession":"agriculture","title":"Answering for your own patch","scenario":"At the season debrief, the owner asks who's been managing the calf shed — and that's you. Your instinct is to deflect ('oh, we all pitch in'). She's asking because the results were good. Take ownership without bragging.","task":"Say a 2-sentence answer that owns the work and shares the one number that shows it.","tips":["Own it plainly: that's been mine since August.","One result: losses down, growth rates up — pick the real one.","Deflecting credit reads as not knowing your own results."],"focus":["impact","concision"],"placeholder":"That's been mine since August. Scour cases are down to two all season, and the"},
    {"id":"presence-agri-early-25","level":"early","profession":"agriculture","title":"The season summary with a spine","scenario":"The owner wants a short end-of-season note from each crew member: how did it go, what should change. Your draft is a humble mush of 'pretty good I think, some stuff could maybe improve.' Give her a verdict, evidence, and one owned recommendation.","task":"Write a 3-4 sentence note: verdict, two facts, one recommendation you stand behind.","tips":["Open with the verdict: a good season with one fixable weak spot.","Two numbers or facts that carry it.","End on one recommendation stated as yours: I'd change X."],"focus":["structure","impact"],"placeholder":"A good season overall — yields up and no lost-time injuries. The weak spot was"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-agri-early-01","level":"early","profession":"agriculture","title":"'Why is milking running late?'","scenario":"The manager strides into the shed at 7:10 and asks why milking's running forty minutes behind. The answer is one broken cup liner and a slow colostrum mob. Your instinct is to start the story at 4:30 am and work forward.","task":"Answer the question in the first sentence, then give the two causes.","tips":["Answer first: we'll be done by 8, forty minutes late.","Then the causes, one line each.","The story of your morning is not an answer to 'why'."],"focus":["clarity","concision"],"placeholder":"We'll be done about 8 — a cup liner split mid-milking and the colostrum mob milked slow."},
    {"id":"pressure-agri-early-02","level":"early","profession":"agriculture","title":"The audit date you don't know","scenario":"The farm assurance inspector asks when the chemical store was last inventoried. You genuinely don't know — the manager handles it. Bluffing an inspector is the worst move on the farm. There's a strong way to say 'I don't know'.","task":"Say an 'I don't know' that names who knows and when you'll have the answer.","tips":["Say it cleanly: I don't know the date.","Immediately attach the path: the manager keeps that log — I can have it for you in ten minutes.","A fast honest 'I don't know' builds more trust than a slow guess."],"focus":["clarity","impact"],"placeholder":"I don't know the exact date — the manager keeps that log. I can get it for you within ten minutes."},
    {"id":"pressure-agri-early-03","level":"early","profession":"agriculture","title":"'How much line left?' — now","scenario":"Mid-haul, the skipper barks down from the wheelhouse: 'How much line left on the drum?' You can see it — maybe a third. Under pressure your mouth wants to narrate the whole haul. He needs one number, this second.","task":"Say the answer as it should come out: number first, nothing before it.","tips":["'About a third' — that's the whole answer.","Add one word of margin if it's tight: 'a third, going fast'.","On deck, every extra word delays the next decision."],"focus":["concision","precision"]},
    {"id":"pressure-agri-early-04","level":"early","profession":"agriculture","title":"'Did you check the fence yesterday?'","scenario":"Stock got out overnight and the owner asks, sharp: 'Did you check the boundary fence yesterday?' The truth is precise: you walked the north and east sides, not the west where they got out. Answer that — exactly — without padding or squirming.","task":"Give the precise answer in one sentence, then what you'll do now.","tips":["Answer exactly what's true: north and east yes, west no.","Don't round up to 'yes' or collapse to 'sort of'.","Follow with the action: I'm walking the west line now."],"focus":["precision","clarity"],"placeholder":"I checked the north and east sides yesterday — not the west, and that's where they got out. I'm heading"},
    {"id":"pressure-agri-early-05","level":"early","profession":"agriculture","title":"The vet's question you can only half answer","scenario":"The vet asks exactly when the calf last drank. You know she took the morning feed at 6 but you weren't there for the midday round. The temptation under her level stare is to guess 'probably lunchtime'.","task":"Say what you know for certain and flag the gap, in 2 sentences.","tips":["Give the solid fact: she drank the full 2 litres at 6 am.","Flag the gap honestly: I wasn't on the midday round — Sam was.","A vet dosing on a guess is worse than a vet who waits one phone call."],"focus":["precision","audience"],"placeholder":"She took her full 2 litres at 6 this morning — I saw that myself. Midday was Sam's round, so I'd"},
    {"id":"pressure-agri-early-06","level":"early","profession":"agriculture","title":"'That count can't be right'","scenario":"You tell the manager the weaner count is 246 and he pushes back flat: 'Can't be — we had 260 in that mob.' You counted twice at the gate. Getting defensive loses the exchange; folding loses the truth.","task":"Say a level reply that stands by the count and offers the check.","tips":["Restate without heat: I counted 246 twice at the gate.","Offer the verification: happy to run them through again with you.","Neither snapping nor caving — just the number and the path to certainty."],"focus":["clarity","impact"],"placeholder":"I counted twice at the gate — 246 both times. Easiest fix is to run them through again together and"},
    {"id":"pressure-agri-early-07","level":"early","profession":"agriculture","title":"Three questions in one breath","scenario":"The manager, phone wedged on his shoulder, fires at you: 'Is the tanker booked, did the vet call back, and where are we on the silage wrap?' Answering in a tangle loses him. Untangle it and answer in order.","task":"Answer all three in three short labeled sentences.","tips":["Take them in the order asked: tanker, vet, wrap.","One sentence each — yes/no plus the key detail.","Numbering out loud ('one... two... three') keeps you both on track."],"focus":["structure","concision"],"placeholder":"Tanker's booked for Thursday 7 am. Vet hasn't called back — I'll chase at noon. Wrap: we've got"},
    {"id":"pressure-agri-early-08","level":"early","profession":"agriculture","title":"'Whose fault was it?'","scenario":"After the heifers got into the crop, the owner asks bluntly: 'Whose fault was that?' You latched the gate; the chain was worn and slipped. The trap is either taking a blame you don't own or sounding like you're dodging one you do.","task":"Answer with the facts of what happened, own your part precisely, and name the fix.","tips":["Facts first: I latched it, the worn chain slipped the hook.","Own exactly your share — no more, no less.","Move fast to prevention: new chain's on, I've checked the others."],"focus":["precision","impact"],"placeholder":"I latched the gate, but the chain's worn and it slipped the hook. I've put a new chain on and checked"},
    {"id":"pressure-agri-early-09","level":"early","profession":"agriculture","title":"Radio answers in the storm","scenario":"A squall's hit mid-muster and the foreman's firing questions over the radio: where's the mob, where's Dee, is the creek crossing passable? Wind's roaring. Long answers get lost; hesitation gets talked over.","task":"Answer the three radio questions in the shortest complete words that carry.","tips":["One fact per transmission: 'Mob's at the yards gate.'","Names and places, no fillers.","If you don't know one, say 'unknown' and move — don't guess in a storm."],"focus":["concision","clarity"]},
    {"id":"pressure-agri-early-10","level":"early","profession":"agriculture","title":"'Can you finish by Friday?'","scenario":"The orchard manager asks if the netting repairs will be done by Friday. Honest answer: yes if the clips arrive Wednesday, no if they don't. The pressure is to just say 'should be fine' and hope.","task":"Give the conditional answer straight: the yes, the condition, and the fallback.","tips":["Structure it: yes, if the clips land Wednesday.","Name the fallback: if they slip, it's Monday.","A conditional yes kept beats a clean yes broken."],"focus":["precision","structure"],"placeholder":"Yes — if the clips arrive Wednesday like the supplier says. If they slip, realistically it's Monday."},
    {"id":"pressure-agri-early-11","level":"early","profession":"agriculture","title":"Correcting the premise politely","scenario":"The owner asks, 'Why did we double the spray rate on the pears?' You didn't — the rate was the same; the volume went up because the new block came online. Answering the question as asked accepts a mistake that didn't happen.","task":"Say a reply that corrects the premise first, then answers the real question.","tips":["Gently reset the fact: the rate didn't change — the area did.","Then answer what she's really asking: why the bill went up.","Correct the record without making her feel corrected."],"focus":["precision","audience"],"placeholder":"The rate's actually unchanged — what went up is the area, since the new block came online. So the"},
    {"id":"pressure-agri-early-12","level":"early","profession":"agriculture","title":"The buyer on the wharf","scenario":"The fish buyer meets the boat and asks, in front of the skipper, 'Quality good this trip?' Most of the catch is excellent; one string sat longer than you'd like. Overselling burns the boat's name; volunteering doubt undersells good fish.","task":"Say an honest, direct answer that leads with the true headline.","tips":["Headline: the bulk is top quality, iced within the hour.","Be straight about the one string if asked — don't volunteer a confession, don't hide from a question.","Your credibility is the boat's brand next trip."],"focus":["audience","precision"],"placeholder":"Bulk of it's excellent — iced within the hour of coming aboard. There's one string I'd grade a step"},
    {"id":"pressure-agri-early-13","level":"early","profession":"agriculture","title":"'Why didn't you call me sooner?'","scenario":"The manager's annoyed: the pump failed at 2 pm and he heard at 5. Truth: you spent three hours trying fixes that nearly worked. Defensiveness ('I was BUSY fixing it') escalates; grovelling helps nobody. Answer the question and give him the rule you'll use next time.","task":"Say a non-defensive answer: the reason, the lesson, the new threshold.","tips":["Answer plainly: I thought I could fix it and kept trying too long.","No counter-attack, no five excuses — one honest reason.","Offer the rule: next time, anything over an hour, I call."],"focus":["clarity","impact"],"placeholder":"Fair. I thought each fix was ten minutes from working and lost three hours that way. New rule from me:"},
    {"id":"pressure-agri-early-14","level":"early","profession":"agriculture","title":"The missing feed records","scenario":"The auditor asks for the calf-feed records for March. You know there's a two-week gap — the whiteboard got wiped before it was copied down. Hiding it risks everything; confessing in a panic spiral helps no one.","task":"State the gap plainly, what exists around it, and the fix that's already in place.","tips":["Say it straight: there's a two-week gap in March.","Give what does exist: complete records either side, and the milk-powder purchase log covers volumes.","Finish with the fix: records now photographed daily before wipe-down."],"focus":["precision","structure"],"placeholder":"There's a gap — two weeks in March where the board was wiped before it was copied. Either side of that"},
    {"id":"pressure-agri-early-15","level":"early","profession":"agriculture","title":"'Is the tractor safe to use?'","scenario":"A casual worker asks if the old tractor is safe to take up the hill paddock. The brakes felt spongy to you yesterday but you haven't had them checked. The pressured answer is 'yeah, should be right.' That phrase, on that hill, could hurt someone.","task":"Say the answer that refuses to guess on safety.","tips":["Don't launder doubt into 'should be fine'.","State what you know: brakes felt spongy yesterday, not checked since.","Give the safe path: take the other tractor, and I'll flag this one now."],"focus":["clarity","impact"],"placeholder":"Not for the hill — the brakes felt spongy yesterday and no one's checked them. Take the John Deere and"},
    {"id":"pressure-agri-early-16","level":"early","profession":"agriculture","title":"The hours challenge","scenario":"The foreman queries your timesheet: 'You've got eleven hours Saturday — that can't be right.' It is right: the water main burst and you were there till dark. Prove it without heat.","task":"Say a calm reply with the facts that verify themselves.","tips":["Anchor to checkable facts: the burst main, the texts you sent at 6 and 8 pm.","Flat tone — the evidence carries the emotion for you.","End with an offer, not a demand: happy to walk you through it."],"focus":["precision","clarity"],"placeholder":"It's right — that's the Saturday the main burst. My texts to you at 6 and 8 that night line up with"},
    {"id":"pressure-agri-early-17","level":"early","profession":"agriculture","title":"The question you didn't catch","scenario":"Over the top of the grain auger, the manager shouts a question and you catch maybe half of it — something about the truck and Tuesday. The pressure move is to nod and answer the question you think it was. On a farm, guessed instructions break things.","task":"Say how you ask for the repeat — specific about what you did catch.","tips":["Kill the auger or step away first if you can.","Repeat the half you got: 'I got truck and Tuesday — say the rest again?'","One repeat costs three seconds; a guessed answer can cost a day."],"focus":["clarity","precision"]},
    {"id":"pressure-agri-early-18","level":"early","profession":"agriculture","title":"'What would YOU do?'","scenario":"The manager is torn on whether to shear early ahead of the cold snap and turns to you: 'What would you do?' The dodge — 'whatever you think, boss' — wastes the question. You've seen the forecast and the wool length. Answer it.","task":"Give a direct answer with your one strongest reason, and own it as yours.","tips":["Pick: I'd shear now, or I'd wait — no middle mush.","One reason, the strongest: the snap is four days out and the shed's free this week.","'It's your call, but that's my answer' is a fine close."],"focus":["impact","concision"],"placeholder":"I'd shear now. The snap's still four days out and the shed and crew are free this week — next week"},
    {"id":"pressure-agri-early-19","level":"early","profession":"agriculture","title":"The neighbour at the fence, angry","scenario":"The neighbour flags you down, furious that spray drifted over his beehives yesterday. You were the one spraying; the wind did shift late in the run. Matching his heat makes it a feud; grovelling admits things you don't know yet.","task":"Say a steady reply: acknowledge, state the facts you know, commit to a follow-up.","tips":["Acknowledge without absorbing blame: I hear you — that's serious.","Facts only: I was spraying, wind shifted about 3, I logged it.","Commit to something concrete: I'll have the manager call you today."],"focus":["audience","clarity"],"placeholder":"That's serious and I want it sorted properly. I was on the sprayer — the wind did shift late in the run,"},
    {"id":"pressure-agri-early-20","level":"early","profession":"agriculture","title":"'How long till the pump's fixed?'","scenario":"The manager asks how long until the transfer pump is running. You've got the casing open and haven't found the fault yet. An invented number will be quoted back at you at noon. There's a better answer than a guess and worse than silence.","task":"Say the estimate with its basis — or the time you'll know by.","tips":["If you can't estimate, timebox the diagnosis: I'll know by 9:30.","If you can, give the basis: if it's the impeller, two hours; if the motor, it's a dealer job.","A time-to-an-answer is a real answer."],"focus":["precision","structure"],"placeholder":"Can't say yet — casing's open but I haven't found it. Give me till 9:30: if it's the impeller, two hours;"},
    {"id":"pressure-agri-early-21","level":"early","profession":"agriculture","title":"Three crews, one radio","scenario":"You're on the base radio when three calls stack up at once: the picking crew needs bins, the sprayer wants a wind check, and a quad's got a flat on the far track. You can't answer all three at once — but you can order them out loud.","task":"Say how you triage on air: acknowledge all three, answer in priority order.","tips":["Acknowledge fast: 'All three copied — sprayer first.'","Priority is safety and stoppages, then supplies.","Telling people their place in the queue is itself an answer."],"focus":["structure","clarity"]},
    {"id":"pressure-agri-early-22","level":"early","profession":"agriculture","title":"'Didn't we already fix this?'","scenario":"The gate latch you repaired last month has failed again and the manager's tone says it: 'Didn't we already fix this?' Yes — and the repeat failure is the actual information. Answer the real question: why is it recurring?","task":"Answer in 3 sentences: yes, what's different this time, what ends the cycle.","tips":["Concede the fact fast: yes, I fixed it in May.","Name the pattern: same latch, same failure — the post is moving, not the latch.","Recommend the cycle-breaker: reset the post, not a third latch."],"focus":["clarity","structure"],"placeholder":"Yes — I replaced the latch in May. Same failure twice means the latch isn't the problem: the post's"},
    {"id":"pressure-agri-early-23","level":"early","profession":"agriculture","title":"Rapid-fire on the owner's walkthrough","scenario":"The owner's doing a fast lap before catching a flight, throwing questions as she walks: calf numbers, silage left, when's the agronomist due. Long answers make her late; vague ones waste the lap. Match her pace without getting sloppy.","task":"Answer three walk-and-talk questions in one crisp line each, and park one for follow-up.","tips":["One line per question, numbers first.","If one needs digging, park it out loud: I'll text you the exact figure by ten.","Matching the asker's tempo is part of the answer."],"focus":["concision","audience"],"placeholder":"Calves: 112 on milk. Silage: about three weeks at current feed-out. Agronomist — I'll confirm and text"},
    {"id":"pressure-agri-early-24","level":"early","profession":"agriculture","title":"The question above your pay grade","scenario":"A visiting buyer asks you, straight out, what price the farm would take for the yearlings. That's the owner's call, not yours — but 'no comment' sounds evasive and guessing could cost real money. There's a clean middle.","task":"Say the answer that gives what you can and routes the rest without flinching.","tips":["Give the part that's yours: their weights, health, and feeding — happy to talk all day.","Route the price cleanly: that's the owner's call — I'll get her to ring you this afternoon.","Confidence in your lane reads better than a fumbled guess outside it."],"focus":["audience","clarity"],"placeholder":"Price is the owner's call, so I'll get her to ring you this afternoon. What I can tell you is their"},
    {"id":"pressure-agri-early-25","level":"early","profession":"agriculture","title":"'Tell me about a mistake' — for the leading-hand job","scenario":"You're interviewing for leading hand and the manager asks the classic: 'Tell me about a mistake you made and what you did.' You have a real one — the wrong paddock sprayed last spring. Under pressure the instinct is to pick something trivial or blur the details.","task":"Answer in 4 sentences: the mistake, the cost, what you did, what changed.","tips":["Pick the real one and name it plainly — that's the whole test.","Structure: mistake, impact, action, change.","End on the system you built, not the guilt you felt."],"focus":["structure","impact"],"placeholder":"Last spring I sprayed the wrong paddock — misread the map and did 7 instead of 9. It cost us the"}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-agri-early-01","level":"early","profession":"agriculture","title":"The before-and-after for a second trough","scenario":"The back paddock has one trough and on hot days the mob queues, the shy heifers miss out, and growth suffers. You want the manager to approve a second trough. A list of plumbing parts won't move him — the change will.","task":"Write a 3-sentence pitch framed as before and after.","tips":["Before: forty head queuing, shy ones drinking last or not at all.","After: two troughs, no queue, even water intake across the mob.","The bridge: one trough, a T-fitting, and a morning's work."],"focus":["structure","impact"],"placeholder":"Right now forty head queue on one trough and the shy heifers drink last or not at all. With a second"},
    {"id":"narrative-agri-early-02","level":"early","profession":"agriculture","title":"Making ear protection real","scenario":"Half the crew shrugs off earmuffs around the chainsaws and the grain dryer. Another lecture about decibels will wash over them. What lands is a stake they can feel — a person, a moment, a loss they'd care about.","task":"Say a 30-second toolbox-talk pitch that makes the stakes human, not statistical.","tips":["One person, one detail: the retired shearer who can't hear his granddaughter on the phone.","Connect it to today: the dryer runs six hours today.","End with the ask, small and concrete: muffs on before it starts, every time."],"focus":["audience","impact"]},
    {"id":"narrative-agri-early-03","level":"early","profession":"agriculture","title":"The loading ramp before someone's hurt","scenario":"The cattle ramp has a rotten board and a gap that grabs boots. Everyone steps over it from habit. You want it fixed this week, before the big consignment. Your case needs stakes, not just a description of rot.","task":"Write a 3-4 sentence message to the manager: the risk, the moment it bites, the fix.","tips":["Paint the moment: loading day, forty head pushing, a boot in that gap.","Stakes in plain terms: a broken ankle and a short crew on the busiest day.","The fix is small — say so: two boards and an hour."],"focus":["impact","structure"],"placeholder":"The ramp's got a rotten board and a boot-trap gap, and Thursday we push forty head over it. If someone"},
    {"id":"narrative-agri-early-04","level":"early","profession":"agriculture","title":"Pre-empting 'it's held so far'","scenario":"You want the skipper to replace the worn hauler rope before next trip. You already know his answer: 'It's held so far.' A pitch that ignores the objection loses to it. A pitch that names it first takes its power away.","task":"Say your pitch, raising and answering 'it's held so far' before he says it.","tips":["Name it yourself: I know it's held so far.","Then reframe: every haul it holds is one haul closer to the one it doesn't.","Price the two outcomes: a rope now, or gear and maybe a hand later."],"focus":["impact","clarity"],"placeholder":"I know the answer's 'it's held so far' — but it's furring at the splice, and every haul it holds is one"},
    {"id":"narrative-agri-early-05","level":"early","profession":"agriculture","title":"Selling the 5 am start in the heatwave","scenario":"A heatwave's coming and you think the crew should start at 5 and knock off at 1. Some will grumble about the alarm. Your pitch at the crew meeting has to make the early start the good deal it actually is.","task":"Say a 3-sentence pitch that frames the change as a trade the crew wins.","tips":["Frame the trade: five cool hours against five brutal ones.","Make the after vivid: done and at the river by 1:30.","Acknowledge the cost honestly — one grim alarm — and weigh it."],"focus":["audience","impact"],"placeholder":"Here's the trade for heatwave week: start at 5, done by 1 — we work the cool and skip the oven."},
    {"id":"narrative-agri-early-06","level":"early","profession":"agriculture","title":"The story that sells the new calf routine","scenario":"You've trialled feeding the calves before yard-cleaning instead of after, and scour cases dropped. Now you need the rest of the crew to switch. Data alone ('cases down 60%') is forgettable; the story of one pen makes it stick.","task":"Tell the 30-second story of the trial pen, ending on the ask.","tips":["Start in the before: pen 2, two sick calves a week, every week.","Turn: swapped the order in June — one case since.","Land the ask: same swap, all pens, starting Monday."],"focus":["structure","audience"],"placeholder":"Pen 2 used to give us two scoury calves a week. In June I started feeding before cleaning instead of"},
    {"id":"narrative-agri-early-07","level":"early","profession":"agriculture","title":"The chainsaw course as an investment","scenario":"You're asking the manager to fund a chainsaw certification course. Framed as 'I'd like some training' it's a cost. Framed as before-and-after for the farm — waiting on contractors versus clearing windfall same-day — it's an investment.","task":"Write a 3-sentence pitch framed around what changes for the farm.","tips":["Before: every windfall waits days for a contractor at call-out rates.","After: cleared same-day, in-house, safely.","Then the price tag, small against one contractor invoice."],"focus":["impact","concision"],"placeholder":"Right now every storm means days of waiting and a contractor invoice. Put me through the two-day"},
    {"id":"narrative-agri-early-08","level":"early","profession":"agriculture","title":"Shade for the yards, in the owner's numbers","scenario":"You want shade cloth over the holding yards. To the owner, comfort talk is soft; production talk is real. You've noticed cows held in the noon sun milk down that evening. Make the stakes concrete in her currency.","task":"Write a 3-4 sentence pitch that converts the problem into the owner's numbers.","tips":["Anchor the stake: hot afternoons, the evening pickup drops — say what you've seen.","Concrete beats general: 'the vat was down on the three hottest days'.","End with cost against loss: shade cloth once, or that dip every summer."],"focus":["audience","precision"],"placeholder":"On the three hottest days last month the evening vat was noticeably down, and each time the herd had"},
    {"id":"narrative-agri-early-09","level":"early","profession":"agriculture","title":"The case for rotating the picking teams","scenario":"The same two pickers always get the low block with the easy fruit, and the rest grind the ladders. Resentment is building and the slow rows are getting slower. You want the orchard manager to rotate teams weekly — pitched as a fix, not a complaint.","task":"Say a 3-sentence pitch: the problem's cost, the rotation, what it fixes.","tips":["Lead with the cost to the orchard, not the unfairness to you: the hard rows are falling behind.","The fix in one line: rotate blocks weekly.","Close with both wins: even pace, even grumbling."],"focus":["structure","audience"],"placeholder":"The ladder rows are falling behind because the same crew always draws them. Rotate the blocks weekly and"},
    {"id":"narrative-agri-early-10","level":"early","profession":"agriculture","title":"Raising the cost objection first","scenario":"You're pitching the manager on upgrading the boundary fence to exclusion netting — and you know his first word will be the price. Say it before he does, next to the number it should be compared with.","task":"Write a 3-4 sentence pitch that opens the money question yourself.","tips":["Name it: yes, it's about $6,000 — here's what that buys against what we lose.","Comparison number: two dog attacks last year cost us more in stock.","An objection you raise yourself becomes evidence you've thought it through."],"focus":["impact","precision"],"placeholder":"The netting's not cheap — about $6,000 for the road boundary. Against that: the two dog attacks last"},
    {"id":"narrative-agri-early-11","level":"early","profession":"agriculture","title":"One incident sells the radios","scenario":"You think the orchard crew needs handheld radios — phones die in the far blocks. You could list five reasons; one true story from last month, when a picker's ladder fall took twenty minutes to reach help, will do more.","task":"Say the pitch built around that single incident, ending with the ask.","tips":["Tell it tight: fall, no signal, twenty minutes of running.","Let the story make the argument — don't add five weaker reasons after it.","Ask for something specific: four radios, one per block crew."],"focus":["impact","concision"],"placeholder":"When Marta came off the ladder in block 7 last month, it took twenty minutes to get help because"},
    {"id":"narrative-agri-early-12","level":"early","profession":"agriculture","title":"The tidy-workshop case, in lost hours","scenario":"The workshop is chaos and everyone's used to it. 'Keep it tidy' has been said a hundred times and changed nothing. What hasn't been said: what the mess actually costs in a week — because you've been counting.","task":"Make the case at the crew meeting using the hours you counted, not the mess itself.","tips":["Lead with the number: I counted — we lost about four hours last week just looking for things.","One vivid example: the grease gun took three of us fifteen minutes.","End with a system, not a scold: shadow board, tools home by knock-off."],"focus":["precision","impact"],"placeholder":"I kept count last week: about four hours, between us, just looking for tools. The grease gun alone took"},
    {"id":"narrative-agri-early-13","level":"early","profession":"agriculture","title":"The small trial that opens the door","scenario":"You believe the new teat spray would cut mastitis, but the manager's wary of switching the whole herd on your say-so. The persuasive move isn't a bigger argument — it's a smaller ask.","task":"Write a 2-3 sentence pitch for a one-mob, one-month trial with a clear success measure.","tips":["Shrink the ask: one mob, one month.","Name the measure up front: compare cell counts against the rest.","A small yes now is worth more than a big maybe forever."],"focus":["structure","precision"],"placeholder":"Let's not switch the herd — just trial the new spray on the front mob for a month and compare cell"},
    {"id":"narrative-agri-early-14","level":"early","profession":"agriculture","title":"The gateway, before and after","scenario":"You pitched the muddy gateway fix and got a 'maybe later.' Time to re-pitch with sharper framing: what every wet morning looks like now, and what the same morning looks like after a day's work with rock and pipe.","task":"Write the before/after re-pitch in 3 sentences.","tips":["Before, vivid: cows bunched at a bog, twenty minutes lost, someone's boot pulled off.","After: they walk through, milking starts on time.","Bridge: one truckload of rock, one culvert, one day."],"focus":["structure","impact"],"placeholder":"Every wet morning now: cows bunched at the bog, twenty minutes lost, and someone digging for a boot."},
    {"id":"narrative-agri-early-15","level":"early","profession":"agriculture","title":"Getting a mate to report the injury","scenario":"Your crewmate jarred his shoulder catching a falling rail and plans to shrug it off — 'she'll be right.' If it worsens unreported, he's got no cover and the farm's got no record. Persuade him, mate to mate, without preaching.","task":"Say what you'd tell him: his stake, in his terms, with the easy next step.","tips":["His stakes, not the rulebook: if it's worse Monday and there's no record, you're on your own.","Make it small: it's a two-minute form, I'll fill it in with you.","One story helps: remember Jack's knee — unreported, then six weeks unpaid."],"focus":["audience","impact"]},
    {"id":"narrative-agri-early-16","level":"early","profession":"agriculture","title":"Icing the catch, priced","scenario":"You've seen the co-op's grading sheets: boxes iced within the hour grade higher than the ones that wait. You want the skipper to change the deck routine so icing never queues behind sorting. Pitch it in dollars, not opinions.","task":"Say the pitch: the grading difference, the routine change, the money.","tips":["Lead with the price gap between grades — the number does the persuading.","The change is cheap: ice first, sort second, one hand swapped over.","Per-trip money times a season makes the case land."],"focus":["precision","impact"],"placeholder":"The co-op sheets show top grade pays 40 cents more a kilo, and grade mostly follows how fast we ice."},
    {"id":"narrative-agri-early-17","level":"early","profession":"agriculture","title":"A first-aid kit on every tractor","scenario":"The nearest first-aid kit is in the shed — fifteen minutes from the back blocks where the cutting and fencing actually happen. You want a kit strapped in every tractor. One remembered afternoon carries this pitch.","task":"Make the case in 3 sentences, built on one real moment.","tips":["Open in the moment: Tom's hand, fencing wire, and a fifteen-minute drive bleeding.","The ask is tiny: a $30 kit zip-tied in each cab.","Close the loop: next time it's a bandage in arm's reach."],"focus":["impact","concision"],"placeholder":"When Tom tore his hand on the wire fencing in the back block, the nearest bandage was fifteen minutes"},
    {"id":"narrative-agri-early-18","level":"early","profession":"agriculture","title":"The 'why' behind the gate order","scenario":"The weekend casuals keep leaving the middle gates open because nobody told them why the order matters — just 'follow the sheet.' A rule with a reason gets followed; a rule without one gets improvised. Write the note that gives the why.","task":"Write a short board note that pairs each gate rule with its one-line reason.","tips":["Rule, then reason: middle gate shut — ram's in with the ewes.","Reasons make rules memorable to people who weren't there Monday.","Keep each pair to one line or it won't get read."],"focus":["audience","clarity"],"placeholder":"Gate rules and the why: MIDDLE GATE SHUT — ram's in with the ewes. YARD GATE CHAINED —"},
    {"id":"narrative-agri-early-19","level":"early","profession":"agriculture","title":"The pay review, framed as value","scenario":"You're asking the owner for a raise after eighteen months. A complaint ('everything costs more') invites sympathy, not money. A record — the rounds you now run alone, the calf results, the machinery tickets you've added — invites a business decision.","task":"Write a 4-sentence ask: the request, three lines of evidence, the close.","tips":["Open with the ask and a number — don't make her guess.","Evidence is what changed since your rate was set: solo milkings, calf-shed results, new tickets.","Close on the future, not a threat: I want to keep building here."],"focus":["structure","impact"],"placeholder":"I'd like to talk about moving my rate to $X. Since we set it I've taken the calf shed solo — losses"},
    {"id":"narrative-agri-early-20","level":"early","profession":"agriculture","title":"The service you shouldn't skip","scenario":"Money's tight and the manager wants to push the header's pre-harvest service to next season. You've heard the bearing noise. Your case: the service is dear, but a mid-harvest breakdown is dearer — and you can price both sides.","task":"Say the case in 3 sentences: cost of servicing, cost of the breakdown, your recommendation.","tips":["Both numbers side by side: $900 service against days of downtime in harvest week.","Add the evidence: the bearing noise is new — it's telling us something.","Recommend, don't hint: service it this month."],"focus":["precision","structure"],"placeholder":"The service is $900, and a bearing letting go mid-harvest is days of downtime at the worst possible"},
    {"id":"narrative-agri-early-21","level":"early","profession":"agriculture","title":"The picture the owner remembers","scenario":"The drainage in the bottom paddock fails every winter and your reports full of 'waterlogging' and 'pugging' blur into the pile. The owner will remember one sharp image longer than a page of terms. Find it.","task":"Sum up the drainage problem in one vivid sentence, then one sentence of ask.","tips":["Make it seeable: every July that paddock is a sponge you can't drive on for six weeks.","One image, not three — pick the strongest.","Follow the picture with the plain ask: drainage quote before autumn."],"focus":["impact","concision"],"placeholder":"Every July the bottom paddock turns into a sponge we can't drive on for six weeks. Can we get a"},
    {"id":"narrative-agri-early-22","level":"early","profession":"agriculture","title":"Answering 'we've always done it this way'","scenario":"You're pitching the two-person lift rule for the wool bales and you can hear the reply already: 'We've thrown bales solo for thirty years.' Meet the objection with respect — and with the thing that changed.","task":"Say the pitch that honours the old way and names what's different now.","tips":["Respect first: it's worked, mostly, for thirty years.","Name the change: the new press packs them 20 kilos heavier.","Recast the rule as skill, not weakness: nobody lifts smart alone at 220 kilos."],"focus":["audience","impact"]},
    {"id":"narrative-agri-early-23","level":"early","profession":"agriculture","title":"Marking the widow-makers first","scenario":"On the new forestry block you can see hung-up branches — widow-makers — through the stand. The schedule's tight and the foreman wants saws running today. You want an hour spent flagging the dangerous trees before anyone cuts. Persuade, fast.","task":"Say a 2-3 sentence case for the marking hour, framed against what it protects.","tips":["Frame the trade: one hour of flagging tape against a helicopter ride.","Be specific about what you saw: three hangers near the track alone.","Offer to do it yourself — an ask with your own labour in it is hard to refuse."],"focus":["impact","clarity"],"placeholder":"Give me one hour with flagging tape before the saws start — I counted three widow-makers near the track"},
    {"id":"narrative-agri-early-24","level":"early","profession":"agriculture","title":"The smoko swap, structured","scenario":"You think smoko should move from 10 to 9:30 during milking season — the gap from a 4:30 start to 10 is too long, and mistakes creep in around 9:45. Pitch it at the crew meeting: the change, the reason, the ask.","task":"Make the two-minute case in three labeled beats: change, reason, ask.","tips":["Change first, one sentence: smoko to 9:30 through milking season.","Reason with evidence: five and a half hours on an empty tank — that's when the near-misses cluster.","Ask for the decision path: trial it for two weeks, then vote."],"focus":["structure","concision"],"placeholder":"Proposal: move smoko to 9:30 for milking season. From a 4:30 start, ten o'clock is five and a half hours"},
    {"id":"narrative-agri-early-25","level":"early","profession":"agriculture","title":"The logbook turned into a story","scenario":"You've kept fuel figures since the tyre pressures got corrected on the two tractors: 8% less diesel over six weeks. In the logbook it's rows of numbers; for the crew meeting it needs to be a one-minute story with a moral — check pressures monthly.","task":"Turn the data into a 3-sentence story: what changed, what the numbers did, what we should adopt.","tips":["Open with the change: we fixed the pressures in May.","Give the numbers a shape: 8% less diesel — about a jerry can a week.","The moral is the ask: pressures checked first Monday, every month."],"focus":["structure","precision"],"placeholder":"Since we corrected the tyre pressures in May, the two tractors have burned 8% less diesel — about a"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-agri-early-01","level":"early","profession":"agriculture","title":"The crop's worse than hoped","scenario":"The manager's been telling the owner the barley would go eight tonnes to the hectare. You've walked it after the dry spell: it's a six-tonne crop, maybe less. He needs the bad number now, not cushioned into a maybe next week.","task":"Say the headline and the basis in 2-3 sentences, bad number first.","tips":["Lead with the number: it's a six-tonne crop, not eight.","Basis in one line: thin heads across the whole north half.","Don't pre-soften with five caveats — the number is the kindness."],"focus":["clarity","impact"],"placeholder":"The barley's going to come in around six tonnes, not eight. The north half's heads are thin from the"},
    {"id":"hard-agri-early-02","level":"early","profession":"agriculture","title":"Saying no to the shift swap","scenario":"A mate asks you to take his Sunday milking so he can go to a wedding. You covered his last two and you're worn thin. 'Maybe, I'll see' just delays the no he needs now to find someone else.","task":"Say a clean, kind no in 2 sentences.","tips":["The no in sentence one — clear, not cold.","One honest reason; you don't owe five.","Help without folding: try Dee, she wanted extra hours."],"focus":["clarity","concision"],"placeholder":"I can't take this one — I've covered the last two and I'm running on empty. Try Dee; she was after"},
    {"id":"hard-agri-early-03","level":"early","profession":"agriculture","title":"The heifer died overnight","scenario":"The heifer the vet treated yesterday died in the night. The owner is fond of her stock and you're dreading the call. Delaying till the manager surfaces just means she hears it late and second-hand.","task":"Say the phone call's first three sentences: the news, the facts, the next step.","tips":["Say it in the first sentence — no long warm-up.","Facts, briefly: treated at 4, checked at 9, gone by morning rounds.","Next step ready: vet's coming for a look at 11, I'll call after."],"focus":["clarity","audience"],"placeholder":"Bad news I'm afraid — we lost the heifer overnight. The vet treated her at 4 and she seemed settled at"},
    {"id":"hard-agri-early-04","level":"early","profession":"agriculture","title":"The gate habit, named","scenario":"A crewmate keeps leaving gates unlatched — third time this month, and this time the calves got into the feed shed. Sniping about it at smoko poisons the crew; saying nothing guarantees a fourth time. Tell him straight: behaviour, impact, ask.","task":"Say the 3-sentence conversation: what happened, what it cost, what you're asking.","tips":["Behaviour, specific: the calf-shed gate, unlatched, third time this month.","Impact without drama: calves in the feed, an hour lost, could've been bloat.","Ask, forward-looking: chain and clip, every time, even for a two-minute job."],"focus":["clarity","impact"],"placeholder":"Mate, the calf-shed gate was unlatched again — third time this month, and this time they got into the"},
    {"id":"hard-agri-early-05","level":"early","profession":"agriculture","title":"Telling the skipper you tore the net","scenario":"You misjudged the drum speed and the net took real damage — a day of mending, maybe two. The skipper's asleep before the next haul. Waking him with bad news is miserable; letting him find it at the winch is worse.","task":"Say how you wake him: the damage, your part, the state of things now.","tips":["Damage first: the net's torn, a day of mending at least.","Your part, plainly: I ran the drum too fast on the haul-back.","What's true now: gear's flaked out, nothing else hurt, we can shoot the spare."],"focus":["clarity","structure"],"placeholder":"Skipper — I've torn the net, my fault, ran the drum too fast on the haul-back. It's a day of mending;"},
    {"id":"hard-agri-early-06","level":"early","profession":"agriculture","title":"The bonus day is off","scenario":"The crew's been promised a paid harvest-completion day off, and the rain that's coming means it's cancelled — they'll be working it instead. You've been asked to tell the crew at day's end. Spin will insult them; plainness will respect them.","task":"Say the announcement in 3 sentences: the news, the reason, what stands instead.","tips":["News first, no wind-up: the bonus day's off — we harvest Saturday.","The reason is one line: rain Monday takes the choice away.","Name what's still true: the day gets paid at overtime, and it moves, not vanishes."],"focus":["clarity","audience"],"placeholder":"Straight up: the bonus day off is cancelled — we're harvesting Saturday. Rain lands Monday and the"},
    {"id":"hard-agri-early-07","level":"early","profession":"agriculture","title":"The unsafe saw habit, said to his face","scenario":"A forestry crewmate cuts one-handed when he's clearing light scrub — quick, casual, and the exact habit that takes fingers. Reporting him first feels like an ambush. The right first move is a direct word, out of everyone else's earshot.","task":"Say the private 2-3 sentence conversation: the habit, the stake, the ask.","tips":["Name the habit exactly — one-handed cuts on the scrub — not 'being careless'.","Stake without preaching: that's the cut that takes fingers, and you like yours.","Make the ask clean: two hands or the saw's down, and it stays between us if it stops."],"focus":["clarity","audience"]},
    {"id":"hard-agri-early-08","level":"early","profession":"agriculture","title":"The season's-end resignation","scenario":"You've taken a job on a bigger operation starting after harvest. The manager's taught you plenty and you dread the text asking to talk. The message needs the news, the date, and the gratitude — without burying the first under the third.","task":"Write the 3-sentence message: the news, the timing, the thanks.","tips":["News in sentence one: I'm finishing up after harvest.","Give the date and the offer: happy to train whoever comes next.","Thanks last, and real — one specific thing he taught you."],"focus":["structure","audience"],"placeholder":"Wanted you to hear it first: I've taken a role at Glendale starting after harvest, so my last day here"},
    {"id":"hard-agri-early-09","level":"early","profession":"agriculture","title":"The missed medicine dose","scenario":"The treatment sheet says the cow in the hospital pen gets antibiotics at 6 am and 6 pm. You missed the morning dose — you've just realised at noon. The vet needs to know, because doubling up or shrugging both have consequences.","task":"Say the call to the vet: the miss, the timing, the question.","tips":["Own it in the first sentence: she missed her 6 am dose — that's on me.","Exact times matter to the vet: last dose 6 pm yesterday.","End on the question: dose now, or wait for tonight?"],"focus":["precision","clarity"],"placeholder":"I need to flag a miss — the hospital-pen cow didn't get her 6 am antibiotics. Last dose was 6 pm"},
    {"id":"hard-agri-early-10","level":"early","profession":"agriculture","title":"No to skipping the pre-start check","scenario":"The foreman's rushed and tells you to skip the harvester pre-start check — 'it ran fine yesterday.' Saying no to the person who rosters you is hard. Saying yes and finding the fault at speed in a dry crop is harder.","task":"Say the respectful refusal: the no, the reason, the cost you're saving.","tips":["A no with a number: it's eight minutes, and I'll do it while you grab the truck.","Reason, not defiance: yesterday's fine doesn't cover today's belts and bearings in a dry crop.","Offer the trade that keeps his schedule whole."],"focus":["clarity","impact"],"placeholder":"I'm going to do the check — it's eight minutes, and I'll have it done while you bring the truck around."},
    {"id":"hard-agri-early-11","level":"early","profession":"agriculture","title":"Short eggs at the farm gate","scenario":"A regular customer drives out every Saturday for four dozen eggs. A fox got into a shed this week and you can only give her two dozen — this week and probably next. She's loyal; she deserves the news before the drive, not at the stall.","task":"Write the text: the shortfall, the plain reason, the options.","tips":["Lead with what changes for her: only two dozen this Saturday.","Reason in half a line — a fox got into one shed.","Give choices: take two, skip a week, or I'll hold the first four next week."],"focus":["audience","clarity"],"placeholder":"Before you drive out Saturday — I can only do two dozen this week. A fox got into one of the sheds."},
    {"id":"hard-agri-early-12","level":"early","profession":"agriculture","title":"The new hand's sorting is too slow","scenario":"The new worker on the grading table is careful but slow — the line backs up behind him every afternoon. He's trying hard, and vague kindness ('you're doing great, just maybe speed up?') will keep him slow. Specific feedback is the kind version.","task":"Say the feedback: the standard, where he is, and the one change to make.","tips":["The number makes it fair: the table needs 12 trays an hour; you're at 8.","One concrete change: grade by the first look — second-guessing is where the time goes.","End with belief and a check-in: you'll have it in a week; let's look again Friday."],"focus":["precision","audience"],"placeholder":"You're careful, and that's the right instinct — now let's get your pace there too. The table needs about"},
    {"id":"hard-agri-early-13","level":"early","profession":"agriculture","title":"The lamb losses, unburied","scenario":"It's been a brutal cold snap and lamb losses in the exposed block are well above normal — 40-odd against a usual dozen. Your report to the owner wants to hide the number in paragraph three. The number is the report.","task":"Write the message with the number in the first sentence and the response underway.","tips":["Number first: we've lost about 40 lambs in the snap, against a normal dozen.","Cause plainly: the exposed block copped the southerly overnight.","Then the response: mobs shifted behind the shelter belt, hay out, count again at dusk."],"focus":["clarity","precision"],"placeholder":"Hard news from the snap: we've lost around 40 lambs, most in the exposed block — usual for a snap is"},
    {"id":"hard-agri-early-14","level":"early","profession":"agriculture","title":"No to lending the tools again","scenario":"The same crewmate wants to borrow your personal socket set — again. Last time it came back short two sockets, and the time before, greasy. You're done lending, but you work beside him every day. The no needs to be clean and final without being a grudge.","task":"Say the no: direct, one reason, no reopening.","tips":["Direct and finished: I've stopped lending the set out.","One reason, no litigation of history: it's come back short twice, so it stays with me now.","Redirect if you want: the farm kit's in the shed and I'll help you find the size."],"focus":["clarity","concision"],"placeholder":"Not this time, mate — I've stopped lending the set out. It's come back short twice, so it stays with"},
    {"id":"hard-agri-early-15","level":"early","profession":"agriculture","title":"The spray that didn't work","scenario":"Ten days after you sprayed the thistles, they're standing green and healthy. The spray — or the timing, or the rate — failed, and re-spraying costs money the manager hasn't budgeted. Telling him early is cheaper than him finding it at cutting time.","task":"Write the 3-sentence message: the failure, the honest possibles, the proposed next step.","tips":["Say it dead straight: the thistle spray hasn't worked.","Possibles without excuse-making: rain at day two, or the rate was light — I'm not sure which.","Propose: agronomist's opinion first, before we spend on a re-spray."],"focus":["clarity","structure"],"placeholder":"The thistle spray hasn't worked — they're green as ever ten days on. Could be the rain on day two or"},
    {"id":"hard-agri-early-16","level":"early","profession":"agriculture","title":"Confessing the dented ute","scenario":"Backing the farm ute past the loading race, you clipped the rail and put a decent dent in the tray-side panel. Nobody saw. The manager will though — Monday, if not sooner. The version he hears from you first is the only good version.","task":"Say the confession: what you did, what it looks like, what you'll do about it.","tips":["No passive voice — 'I dented the ute', not 'the ute got dented'.","Describe it honestly: tray-side panel, decent dent, no mechanical damage.","Offer the make-good: photos taken, happy to sort the panel beater or have it off my pay."],"focus":["clarity","impact"],"placeholder":"Before you spot it Monday — I dented the ute backing past the race. Tray-side panel, cosmetic, nothing"},
    {"id":"hard-agri-early-17","level":"early","profession":"agriculture","title":"The casual who isn't coming back","scenario":"A well-liked casual worker has been let go over repeat no-shows, and the manager's asked you to tell the picking crew before shift so the rumour mill doesn't do it worse. It's not your decision to defend or trash — just to deliver cleanly.","task":"Say the 2-3 sentence announcement: plain, respectful, no editorialising.","tips":["Plain fact: Ryan's finished up and won't be back this season.","Don't relitigate the reasons or perform sadness — either invites the pile-on.","Land on what changes for them: we're one down till Thursday, so rows re-pair today."],"focus":["audience","concision"]},
    {"id":"hard-agri-early-18","level":"early","profession":"agriculture","title":"Boots in the milk room","scenario":"Someone's been walking yard boots into the milk room — there's muck by the vat two mornings running, and the tanker driver noticed. A passive-aggressive sign ('SOME PEOPLE seem to think...') makes it worse. Write the note that's blunt and blame-free.","task":"Write a 2-sentence board note: the standard, the reason, no sarcasm.","tips":["State the rule, not the crime: milk room is clean-boots-only, no exceptions.","One line of stakes: muck by the vat risks a failed pickup.","Skip the detective work in public — handle repeat offenders in person."],"focus":["clarity","audience"],"placeholder":"Milk room is clean-boots-only — swap at the door, every time. Muck by the vat can fail us a whole"},
    {"id":"hard-agri-early-19","level":"early","profession":"agriculture","title":"Seasick and saying so","scenario":"Six hours into a three-day trip, you're seasick past the point of working safely — you can't hold footing on the wet deck. Toughing it out sounds noble and gets someone hurt on the winch. Telling the skipper feels like failure. It isn't; it's a report.","task":"Say it to the skipper: your state, what you can't do safely, what you can.","tips":["Report, don't apologise: I'm past working the deck safely.","Be specific about the line: I can't trust my footing at the winch.","Offer what's left: I can bait, ice, and keep the galley going."],"focus":["clarity","precision"]},
    {"id":"hard-agri-early-20","level":"early","profession":"agriculture","title":"Feedback up: the changing instructions","scenario":"Twice this week the manager set the day's plan at 6 am and changed it by 9, and both times half the crew worked an hour on the dead plan. He's approachable — but nobody's actually told him the cost. That's yours to do, respectfully and specifically.","task":"Say the 3-sentence upward feedback: pattern, cost, request.","tips":["Pattern with dates, not 'you always': Tuesday and Thursday both flipped by 9.","Cost in his terms: about three crew-hours each time.","Request one mechanism: a 9 am check-in text before anyone re-rigs gear."],"focus":["audience","structure"],"placeholder":"Can I flag one thing from this week? Tuesday and Thursday the plan changed after we'd rigged for the"},
    {"id":"hard-agri-early-21","level":"early","profession":"agriculture","title":"Turning down the weekend overtime","scenario":"The manager asks you to work both weekend days — third weekend running. You need this one; you promised your family. Free workers say yes resentfully and burn out. The clean no keeps both the weekend and the relationship.","task":"Say the decline: the no, one reason, and the alternative you can offer.","tips":["No first, warm but whole: I can't do this weekend.","One reason, undefended: I've promised the family this one.","Alternative that's real: I'll do early starts Monday to Wednesday, or next weekend's mine."],"focus":["clarity","concision"],"placeholder":"I can't do this weekend — I've promised it to the family, third one in a row. What I can do is early"},
    {"id":"hard-agri-early-22","level":"early","profession":"agriculture","title":"Hail took the Galas","scenario":"A twenty-minute hailstorm just went through block 3. You've walked two rows: most of the Galas are pocked — process grade now, not premium. The orchard manager is off-site and needs the damage headline before the insurance clock and the packing plan both slip.","task":"Write the text: damage estimate first, basis, and the two clocks ticking.","tips":["Headline the loss: Galas in block 3 look 70-80% pocked — process grade.","Basis: two rows walked, photos taken.","Name the clocks: insurer wants notice fast, and the packing plan needs re-cutting today."],"focus":["clarity","precision"],"placeholder":"Hail's hit block 3 — I'd say 70-80% of the Galas are pocked, process grade now. Walked two rows,"},
    {"id":"hard-agri-early-23","level":"early","profession":"agriculture","title":"The neighbour's dog and the ewes","scenario":"You saw the neighbour's dog in with the ewes this morning — no kills, but the mob's rattled and one's limping. The neighbour is a decent bloke and this conversation decides whether it stays neighbourly. Facts, stakes, and a clear ask — no fury, no mush.","task":"Say the doorstep conversation in 3-4 sentences.","tips":["Facts first: your dog was in with my ewes at 7 this morning — I watched him ten minutes.","Stakes said evenly: next time it's dead lambs, and the law's ugly about stock-worrying dogs.","One clear ask: he stays tied or fenced, starting today."],"focus":["audience","impact"],"placeholder":"Morning — need to talk about your dog. He was in with my ewes at 7 today; no kills, but one's limping"},
    {"id":"hard-agri-early-24","level":"early","profession":"agriculture","title":"The earbuds on the felling block","scenario":"Your mate cuts with both earbuds in, music up — he can't hear shouted warnings or the crack of a stem going early. You're his workmate, not his boss, and the last bloke who got lectured dug in harder. Say it once, straight, in terms he actually values.","task":"Say the one-to-one: the habit, the specific danger, the ask — under 30 seconds.","tips":["Specific over general: with both buds in you missed Blake's warning shout on Tuesday.","His currency: you've got a kid — hear the tree that's coming for you.","A workable ask beats a perfect one: one ear out on the block, always."],"focus":["audience","impact"]},
    {"id":"hard-agri-early-25","level":"early","profession":"agriculture","title":"Announcing the visitor ban","scenario":"Bird flu's been confirmed two farms over, and from today it's boots dipped, sheds locked, and no visitors — including the school group booked for Friday and the neighbour who wanders in for eggs. You're writing the note for the gate and the message for the group chat.","task":"Write the plain 3-sentence announcement: the rule, the reason, the duration.","tips":["Rule first, absolute: no visitors on-farm until further notice.","Reason in one line: confirmed bird flu two farms over — we're protecting the flock.","Say what happens to existing plans: Friday's school visit is cancelled; eggs at the gate stall only."],"focus":["clarity","impact"],"placeholder":"From today: no visitors on-farm until further notice. Bird flu's confirmed two farms over and we're"}
  ],
  "putting-it-together": [
    {"id":"together-agri-early-01","level":"early","profession":"agriculture","title":"The complete shift handoff","scenario":"You're off for two days and the relief milker takes over tonight. Everything you know has to land in one message: the cow on antibiotics whose milk must stay out of the vat, the sticky gate on pen 4, the vet's re-check Thursday. One message, everything, in the right order.","task":"Write the full handoff: critical first, routine after, nothing missing.","tips":["Lead with the can't-miss: cow 214's milk stays OUT of the vat till Friday.","Then time-bound items: vet re-check Thursday 10 am.","Routine quirks last: pen 4 gate needs a lift-and-shove."],"focus":["structure","clarity"],"placeholder":"Top priority: cow 214 is on antibiotics — her milk stays OUT of the vat until Friday. Second: vet's"},
    {"id":"together-agri-early-02","level":"early","profession":"agriculture","title":"Same failure, three channels","scenario":"The stock-water pump has failed with a heatwave forecast. Three messages, three audiences: a radio call to the crew working the far blocks, a text to the manager in town, and a board note for whoever wanders in. Same fact — three different shapes.","task":"Write all three: the radio call, the text, and the board note.","tips":["Radio: shortest, action-first — troughs won't refill, check them on your block now.","Text to manager: fact, impact, ask — pump's dead, 35° forecast, need the repair call today.","Board note: rule-shaped — pump's down, carting water, don't move mobs without checking troughs."],"focus":["audience","structure"],"placeholder":"Radio: 'All crews — stock pump's down, troughs won't refill. Eyeball every trough on your block and"},
    {"id":"together-agri-early-03","level":"early","profession":"agriculture","title":"The quad rollover near-miss, in full","scenario":"A casual worker rolled a quad on the wet track by the dam — thrown clear, bruised, helmet did its job. You saw it. The incident report form gives you six blank lines: what happened, why, and what stops the next one. This is the whole course in six lines.","task":"Write the complete incident report: event, conditions, cause, injury, response, prevention.","tips":["Facts in time order, times included: 8:40 am, wet track, downhill turn above the dam.","Separate what you saw from what you conclude — label your read.","Prevention that's specific: speed limit on that track when wet, and it's in the induction now."],"focus":["structure","precision"],"placeholder":"8:40 am: J. rolled the quad on the downhill turn above the dam. Track was wet from overnight rain;"},
    {"id":"together-agri-early-04","level":"early","profession":"agriculture","title":"The 90-second toolbox talk","scenario":"You're running this morning's toolbox talk: rain from noon changes the job order, the agronomist's on-site at 10, and there's a new hazard — wasps nesting by the fuel shed. Ninety seconds, signposted, and everyone walks away knowing their day.","task":"Say the whole talk: signpost, three items in order, one-line close.","tips":["Map first: weather, visitor, hazard — three things.","Job order changes get names attached: Sam and Dee switch to the shed job at noon.","Close by checking the one dangerous item landed: everyone clear on the wasps?"],"focus":["structure","concision"]},
    {"id":"together-agri-early-05","level":"early","profession":"agriculture","title":"The Friday report the owner actually reads","scenario":"The owner asks for a short weekly note each Friday. Yours have been diaries — long, dutiful, unread. This week had a headline (silage done, 480 bales), a number that matters (two mastitis cases, both treated), and one decision she owes you (the fencing quote).","task":"Write the Friday note: headline, two facts, one clearly-flagged decision needed.","tips":["Headline first: silage's done — 480 bales, 40 up on last year.","Facts in one line each, numbers in.","Flag the ask so it can't be missed: DECISION NEEDED on the fencing quote by Wednesday."],"focus":["structure","concision"],"placeholder":"Silage is done: 480 bales, about 40 up on last year. Two mastitis cases this week, both treated and"},
    {"id":"together-agri-early-06","level":"early","profession":"agriculture","title":"The storm-prep message with everything","scenario":"A serious front arrives tomorrow afternoon: 90 km/h gusts and 40 mm. Every loose thing on the farm is your problem tonight. One group message has to move the whole crew: what gets done today, in what order, by whom, and what's the line for 'good enough'.","task":"Write the crew message: priorities ordered, names attached, done-by time.","tips":["Order by consequence: irrigation off the low block first, then hay under cover, then loose iron.","A name on every job — 'someone should' means no one will.","End with the bar and the deadline: everything tied down or inside by 4 pm."],"focus":["structure","impact"],"placeholder":"Storm hits tomorrow arvo — 90k gusts. Today, in this order: 1) Sam — pull the irrigation gear off the"},
    {"id":"together-agri-early-07","level":"early","profession":"agriculture","title":"The voicemail and the follow-up text","scenario":"A cow is calving badly and the regular vet isn't answering. You leave a voicemail, then back it with a text — the pair has to work together: the voicemail carries urgency and the ask; the text carries the details her thumb can act on.","task":"Say the 20-second voicemail, then write the follow-up text.","tips":["Voicemail: emergency, farm name, callback number — twice.","Text: the triage facts — heifer, first calf, feet showing for an hour, no progress.","Don't duplicate; the two should stack, not repeat."],"focus":["audience","precision"],"placeholder":"Voicemail: 'It's Sam at Riverbend — calving emergency, first-calver stuck, need a call back on"},
    {"id":"together-agri-early-08","level":"early","profession":"agriculture","title":"Eight sentences down to three","scenario":"Your draft to the manager about the weaner sale runs eight sentences: two of weather, one apology, three of process, and — buried — the two that matter: 84 weaners ready, and the buyer wants an answer by Friday. Edit like the course taught you.","task":"Cut the draft to 3 sentences that keep everything that matters.","tips":["Find the buried lead: 84 ready, buyer needs an answer Friday.","Delete the weather, the apology, and the process tour.","Read it back once: does each sentence earn its place?"],"focus":["concision","impact"],"placeholder":"84 weaners are sale-ready and the buyer needs our answer by Friday. Average weight's 285 kg, up on"},
    {"id":"together-agri-early-09","level":"early","profession":"agriculture","title":"Two weeks of leave, one page of notes","scenario":"You're finally taking two weeks off. Whoever covers you gets one page: the daily rhythm, the animals with histories, the machine quirks, the numbers to call. Written for a stranger — because it might be one.","task":"Write the handover page: routines, watch-list, quirks, contacts — ordered for a stranger.","tips":["Day shape first: what happens at 5, 7, noon, 4.","Watch-list with why: the ewe with the black tag went down last month — check her daily.","Quirks that bite: the pump primes twice; contacts with names and when to use them."],"focus":["audience","structure"],"placeholder":"THE DAY: 5 am cows in, 7 am calves fed (mix on the board), noon trough run, 4 pm cows again."},
    {"id":"together-agri-early-10","level":"early","profession":"agriculture","title":"Injury on deck — the full call","scenario":"A crewmate's hand is crushed between a pot and the rail — bleeding controlled but he's done, and you're four hours out. You're on the radio to the skipper below, then the coast guard channel. Structure under stress: who, what, where, what you need.","task":"Say the two calls: the shout to the skipper, then the structured radio call for help.","tips":["To the skipper: injury, who, how bad, where on deck — five seconds.","To the radio: vessel name, position, casualty status, assistance requested — in that order.","Slow your voice down one gear; speed loses words on a radio."],"focus":["structure","clarity"]},
    {"id":"together-agri-early-11","level":"early","profession":"agriculture","title":"One rule, two audiences","scenario":"New biosecurity rule after the neighbour's outbreak: all vehicles disinfect at the gate. The manager needs the formal version for the record; the crew group chat needs the version that actually changes Monday-morning behaviour. Same rule, two registers.","task":"Write both: the note to the manager and the group-chat version.","tips":["Manager version: the rule, the trigger, the compliance detail — tidy and file-able.","Crew version: what you do differently tomorrow, in ten seconds of reading.","Neither version jokes about biosecurity — register isn't the same as jokiness."],"focus":["audience","clarity"],"placeholder":"To manager: 'From tomorrow all vehicles disinfect at the front gate — outbreak confirmed at Hansen's."},
    {"id":"together-agri-early-12","level":"early","profession":"agriculture","title":"The harvest-day brief","scenario":"Tomorrow is the biggest day of the season: two headers, three trucks, eight people, rain possible by 5 pm. Tonight's group message is the plan — who's where at 6 am, the order of blocks, the cut-off call, and who makes it.","task":"Write the harvest-day brief: positions, sequence, decision points, weather cut-off.","tips":["People to places to times: Dee on header 1, east block, rolling by 6:30.","Name the decision-maker for the rain call — one person, said now.","Build in the check: everyone thumbs-up this message tonight."],"focus":["structure","precision"],"placeholder":"Tomorrow, 6 am start. Dee — header 1, east block. Marco — header 2, follows into the creek block."},
    {"id":"together-agri-early-13","level":"early","profession":"agriculture","title":"The lambing tally, with a verdict","scenario":"Lambing's done and the owner wants the wrap-up: how did we actually do? You've got the numbers — 148% lambing, losses at 8%, the exposed block worst again. A pile of percentages isn't an answer. Verdict, evidence, and next year's one change.","task":"Write the 4-sentence season wrap: verdict, two numbers, one recommendation.","tips":["Verdict up top: a good season — best tally in three years.","Two numbers that prove it, one that qualifies it.","End with next year's change: shelter belt or later mob in the exposed block."],"focus":["structure","impact"],"placeholder":"A good lambing — 148%, the best in three years. Losses ran 8%, and most of them were the exposed"},
    {"id":"together-agri-early-14","level":"early","profession":"agriculture","title":"The wet-weather gear ask, complete","scenario":"The crew's wet-weather gear is dead — cracked jackets, boots that leak. You're making the full case to the manager in one message: what's needed, what it costs, why now, and what the farm gets. Recommendation-shaped, not complaint-shaped.","task":"Write the complete ask: recommendation, cost, timing, payoff.","tips":["Open on the recommendation: replace the crew's wet gear before winter — about $180 a head.","Why now in one line: three of five jackets are cracked through.","Payoff the manager cares about: dry crew, full days, nobody 'sick' on the wet ones."],"focus":["structure","audience"],"placeholder":"Recommendation: replace the crew's wet-weather gear before winter — five sets, about $180 each."},
    {"id":"together-agri-early-15","level":"early","profession":"agriculture","title":"The escalation with history","scenario":"The transfer pump has now failed four times in six weeks, patched each time. You're done patching — this needs the manager to choose: rebuild or replace. Your message needs the history compressed, the options priced, and your recommendation owned.","task":"Write the escalation: one-line history, two options with costs, your pick.","tips":["Compress the history to one line with numbers: four failures, six weeks, a day lost each time.","Two options, one line each, priced: rebuild ~$800, replace ~$2,400.","Then own the call: I'd replace — the casing's pitted and rebuilds won't hold."],"focus":["structure","impact"],"placeholder":"The transfer pump's failed four times in six weeks — about a day lost each round. Two ways out:"},
    {"id":"together-agri-early-16","level":"early","profession":"agriculture","title":"The hazard, closed out end-to-end","scenario":"You spot a snapped strainer wire under tension across the laneway — a real injury waiting. The full loop is four messages: the radio flag right now, the board note for the day, the text telling the manager, and tomorrow's follow-up confirming the fix. Run the whole loop.","task":"Write all four: radio call, board note, manager text, next-day follow-up.","tips":["Radio: danger and location, nothing else — 'snapped strainer under tension, north laneway, keep clear'.","Board note adds the barrier tape detail; manager text adds the ask for the fencing gear.","The follow-up is the forgotten one — 'fixed and cleared' closes the loop for everybody."],"focus":["structure","clarity"],"placeholder":"Radio: 'All stations — snapped strainer wire under tension across the north laneway. Keep clear, I'm"},
    {"id":"together-agri-early-17","level":"early","profession":"agriculture","title":"The welcome note for the next new hand","scenario":"A new worker starts Monday and the manager asks you — the last new person — to write the first-day note. You remember what confused you: the nicknames, the unspoken rules, where anything is. Write the note you wish you'd been handed.","task":"Write the first-morning note: arrival, who's who, the three unwritten rules, where to ask.","tips":["Assume zero context: 'the far shed' needs a landmark, people need names and jobs.","The unwritten rules are the gold: gates, radio manners, whose mug not to use.","End with a safe person to ask: find me — no question's too small."],"focus":["audience","clarity"],"placeholder":"Welcome — park behind the big green shed, boots on by 6:50. You'll meet Dee (dairy, in charge of"},
    {"id":"together-agri-early-18","level":"early","profession":"agriculture","title":"The missed irrigation set, owned and fixed","scenario":"You forgot to move the irrigation last night; the low corner flooded and the top block missed its water on the hottest week of the year. The message to the manager needs the whole kit: plain confession, the damage sized honestly, the fix, and the system that stops a repeat.","task":"Write the message: what happened, the impact, today's fix, the prevention.","tips":["Own it in five words, then move: I missed the 9 pm shift.","Size the damage without minimising or catastrophising: low corner pooled, top block a day behind.","The prevention is the redemption: phone alarm plus the checklist by the shed door."],"focus":["clarity","structure"],"placeholder":"My miss — I didn't move the irrigation at 9 last night. Low corner's pooled and the top block lost a"},
    {"id":"together-agri-early-19","level":"early","profession":"agriculture","title":"Three topics, two minutes, one room","scenario":"Crew meeting. You've got the floor for two minutes and three things to land: the water-trough repair schedule, the new gate rule, and a thank-you to the weekend crew. Signpost, deliver, land — no drift, no 'one more thing' after you sit down.","task":"Say the whole two minutes: signposted open, three items, clean close.","tips":["Signpost: three things, forty seconds each.","Order them so the rule — the one that needs remembering — goes last.","Close with the close: 'that's all three' beats trailing off."],"focus":["structure","concision"]},
    {"id":"together-agri-early-20","level":"early","profession":"agriculture","title":"Same breakdown, two readers","scenario":"The feed mixer's gearbox is gone. The mechanic needs the technical text: model, symptoms, what you've checked. The owner needs a different text: what it means for feeding, the cost bracket, and when it's back. Write both without mixing the registers.","task":"Write the two texts: mechanic version and owner version.","tips":["Mechanic: model number, the grinding on startup, the metal in the oil — findable facts.","Owner: cows still get fed (the backup plan), likely cost bracket, days not part numbers.","The skill is what you leave OUT of each."],"focus":["audience","precision"],"placeholder":"To mechanic: 'Keenan 340 mixer — loud grinding from the gearbox on startup, metal flakes in the drain"},
    {"id":"together-agri-early-21","level":"early","profession":"agriculture","title":"The case for keeping you on","scenario":"The season's ending and the farm keeps one worker year-round. The manager asks each of you: why you? This is every module at once — verdict, evidence, audience, concision — in ninety seconds, without arrogance and without shrinking.","task":"Say your 90-second case: claim, three evidenced strengths, the close.","tips":["Claim first, plainly: keep me — here's the case in three parts.","Evidence beats adjectives: the calf-shed numbers, the pump rebuilds, the weekend cover you never refused.","Close forward: what you'd take on next year, not just what you did."],"focus":["impact","structure"],"placeholder":"I'd like the year-round spot, and here's my case in three parts. First, results: the calf shed ran at"},
    {"id":"together-agri-early-22","level":"early","profession":"agriculture","title":"The inspection-eve board note","scenario":"The farm assurance inspector arrives at 9 tomorrow. Everything the crew must remember — records book on the bench, chemical store locked and listed, that one gate chained, clean overalls — has to fit on one board note people will actually read at 5:30 am.","task":"Write the board note: everything needed, nothing extra, skimmable in ten seconds.","tips":["Five lines maximum, one instruction each, most-forgettable first.","Write instructions, not vibes: 'records book ON the bench' beats 'be ready'.","Put a name by the two items that need an owner."],"focus":["concision","clarity"],"placeholder":"INSPECTOR 9 AM. 1) Records book out on the bench — Dee. 2) Chem store locked, list on the door —"},
    {"id":"together-agri-early-23","level":"early","profession":"agriculture","title":"Briefing the relief skipper","scenario":"The skipper's ashore for a family emergency and a relief skipper takes the boat out tomorrow. You're the crew member who knows her quirks: the port engine's slow cold start, the winch brake that needs two pumps, the sounder that reads shallow. Brief him like his trip depends on it.","task":"Give the spoken briefing: safety-critical quirks first, then handling, then housekeeping.","tips":["Rank by what could hurt someone: the winch brake before the sticky galley drawer.","For each quirk: what it does, what you do about it — pairs, not puzzles.","Finish by asking him to read the critical two back."],"focus":["structure","audience"]},
    {"id":"together-agri-early-24","level":"early","profession":"agriculture","title":"The frost-loss package","scenario":"A late frost has taken maybe 40% of the stone-fruit crop. The owner's message needs the whole bad-news package in one: the headline loss, the numbers behind it, the two paths forward (thin hard and save quality, or push volume on what's left), and what you need from her.","task":"Write the complete message: headline, evidence, two options, recommendation, ask.","tips":["Headline is the number: frost took roughly 40% of the stone fruit.","Evidence in one line: walked all four blocks, worst on the low ground.","Options priced in outcomes, then your pick — and the deadline for her call."],"focus":["structure","impact"],"placeholder":"Last night's frost took roughly 40% of the stone fruit — I've walked all four blocks, and the low"},
    {"id":"together-agri-early-25","level":"early","profession":"agriculture","title":"Your own draft, against the checklist","scenario":"Your end-of-season message to the owner is drafted: it's honest, warm — and long, point-last, and vague in two places where numbers exist. Before sending, run it against everything: point first? structure visible? every sentence earning its place? numbers where numbers belong?","task":"Rewrite your draft to pass the full checklist: lead, structure, concision, precision.","tips":["Find your best sentence — it's probably buried; move it to the top.","Replace 'went well' and 'a few issues' with the real numbers.","Cut a third; if nothing hurts to lose, you haven't cut enough."],"focus":["concision","structure"],"placeholder":"Thanks for a great season — here's my wrap in four lines. Headline: the best calf-rearing numbers the"}
  ]
};
